function nowIso() {
  return new Date().toISOString();
}

function json(data, status = 200, extraHeaders = {}) {
  return new Response(JSON.stringify(data), {
    status,
    headers: { ...JSON_HEADERS, ...extraHeaders }
  });
}

function fail(message, status = 400, code = "BAD_REQUEST") {
  return json({ success: false, error: message, code }, status);
}

function id(prefix = "id") {
  return prefix + "_" + crypto.randomUUID().replace(/-/g, "");
}

function clampInt(value, min = 0, max = Number.MAX_SAFE_INTEGER) {
  const n = Number.parseInt(String(value), 10);
  if (!Number.isFinite(n)) return min;
  return Math.max(min, Math.min(max, n));
}

function cleanText(value, max = 200) {
  return String(value ?? "").trim().slice(0, max);
}

function canonicalAppUrl(value, fallbackOrigin) {
  try {
    const base = new URL(fallbackOrigin).origin;
    const parsed = new URL(cleanText(value, 500) || base, base);
    // Telegram Web Apps require HTTPS outside local development.
    if (!["localhost", "127.0.0.1", "::1"].includes(parsed.hostname)) parsed.protocol = "https:";
    parsed.username = "";
    parsed.password = "";
    parsed.search = "";
    parsed.hash = "";
    parsed.pathname = "/app";
    return parsed.toString();
  } catch (_) {
    return new URL("/app", fallbackOrigin).toString();
  }
}

function normalizeUsername(value) {
  let text = String(value || "").toLowerCase().replace(/[^a-z0-9_]/g, "");
  if (!text) text = "reseller_" + Math.random().toString(36).slice(2, 9);
  if (!/^[a-z]/.test(text)) text = "u_" + text;
  return text.slice(0, 32);
}

function randomPassword(length = 16) {
  const upper = "ABCDEFGHJKLMNPQRSTUVWXYZ";
  const lower = "abcdefghijkmnopqrstuvwxyz";
  const digits = "23456789";
  const special = "!@#$%^&*_-+";
  const all = upper + lower + digits + special;
  const pick = chars => chars[crypto.getRandomValues(new Uint8Array(1))[0] % chars.length];
  const out = [pick(upper), pick(upper), pick(lower), pick(lower), pick(digits), pick(digits), pick(special)];
  while (out.length < Math.max(12, length)) out.push(pick(all));
  for (let i = out.length - 1; i > 0; i--) {
    const j = crypto.getRandomValues(new Uint32Array(1))[0] % (i + 1);
    [out[i], out[j]] = [out[j], out[i]];
  }
  return out.join("");
}

function validatePasarguardPassword(password, username = "") {
  const errors = [];
  if (new TextEncoder().encode(password).length > 72) errors.push("حداکثر طول رمز ۷۲ بایت است");
  if (password.length < 12) errors.push("رمز باید حداقل ۱۲ کاراکتر باشد");
  if ((password.match(/\d/g) || []).length < 2) errors.push("رمز باید حداقل ۲ عدد داشته باشد");
  if ((password.match(/[A-Z]/g) || []).length < 2) errors.push("رمز باید حداقل ۲ حرف بزرگ انگلیسی داشته باشد");
  if ((password.match(/[a-z]/g) || []).length < 2) errors.push("رمز باید حداقل ۲ حرف کوچک انگلیسی داشته باشد");
  if (!/[!@#$%^&*()\-_=+\[\]{}|;:,.<>?/~`]/.test(password)) errors.push("رمز باید حداقل یک نماد ویژه داشته باشد");
  if (username && password.toLowerCase().includes(username.toLowerCase())) errors.push("رمز نباید شامل نام کاربری باشد");
  if (password.includes('"')) errors.push("استفاده از علامت نقل‌قول دوتایی در رمز مجاز نیست");
  return errors;
}

async function parseBody(request) {
  try {
    return await request.json();
  } catch {
    return {};
  }
}

async function getSettings(env) {
  await ensureDb(env);
  const currentTime = Date.now();
  if (settingsCache && currentTime - settingsCacheAt < SETTINGS_CACHE_TTL_MS) return { ...settingsCache };
  const result = await env.PASARGUARD_DB.prepare("SELECT key, value FROM app_settings").all();
  const settings = { ...DEFAULT_SETTINGS };
  for (const row of result.results || []) settings[row.key] = row.value;
  const legacy = {
    bot_token: "BOT_TOKEN", admin_ids: "ADMIN_IDS", auth_max_age_seconds: "AUTH_MAX_AGE_SECONDS",
    allow_dev_auth: "ALLOW_DEV_AUTH", dev_telegram_id: "DEV_TELEGRAM_ID",
    app_encryption_key: "APP_ENCRYPTION_KEY", app_url: "APP_URL",
    telegram_webhook_secret: "TELEGRAM_WEBHOOK_SECRET",
    pasarguard_panel_url: "PASARGUARD_PANEL_URL", pasarguard_access_token: "PASARGUARD_ACCESS_TOKEN",
    pasarguard_admin_username: "PASARGUARD_ADMIN_USERNAME", pasarguard_admin_password: "PASARGUARD_ADMIN_PASSWORD",
    pasarguard_reseller_role_id: "PASARGUARD_RESELLER_ROLE_ID", pasarguard_reseller_role_name: "PASARGUARD_RESELLER_ROLE_NAME",
    pasarguard_sales_role_id: "PASARGUARD_SALES_ROLE_ID", pasarguard_sales_role_name: "PASARGUARD_SALES_ROLE_NAME",
    pasarguard_master_role_id: "PASARGUARD_MASTER_ROLE_ID", pasarguard_master_role_name: "PASARGUARD_MASTER_ROLE_NAME",
    pasarguard_set_telegram_id: "PASARGUARD_SET_TELEGRAM_ID", pasarguard_admin_data_limit_bytes: "PASARGUARD_ADMIN_DATA_LIMIT_BYTES",
    pasarguard_sub_domain: "PASARGUARD_SUB_DOMAIN", pasarguard_support_url: "PASARGUARD_SUPPORT_URL",
    github_repo: "GITHUB_REPO", github_token: "GITHUB_TOKEN", cf_account_id: "CF_ACCOUNT_ID",
    cf_api_token: "CF_API_TOKEN", cf_worker_name: "CF_WORKER_NAME"
  };
  for (const [key, envKey] of Object.entries(legacy)) {
    if (!settings[key] && env[envKey] !== undefined) settings[key] = String(env[envKey]);
  }
  settingsCache = Object.freeze({ ...settings });
  settingsCacheAt = currentTime;
  return { ...settingsCache };
}

function settingFlag(value, defaultValue = true) {
  if (typeof value === "boolean") return value;
  if (value === null || value === undefined || String(value).trim() === "") return Boolean(defaultValue);
  const normalized = String(value).trim().toLowerCase();
  if (["false", "0", "off", "no", "disabled", "closed"].includes(normalized)) return false;
  if (["true", "1", "on", "yes", "enabled", "open"].includes(normalized)) return true;
  return Boolean(defaultValue);
}

function resellerBotSalesOpen(settings) {
  return settingFlag(settings?.reseller_bot_sales_enabled, true);
}

function normalizeResellerLicenseType(value) {
  return String(value || "store").toLowerCase() === "master" ? "master" : "store";
}

function resellerLicenseTypeLabel(value) {
  return normalizeResellerLicenseType(value) === "master" ? "مستر نمایندگی" : "نماینده فروش";
}

function resellerHasIndependentPanel(bot) {
  return Boolean(bot) && !bot.parent_bot_id && String(bot.purchase_source || "central") === "central";
}

function resellerBotCanCreateDownline(bot) {
  return resellerHasIndependentPanel(bot) && normalizeResellerLicenseType(bot?.license_type) === "master";
}

function centralMinimumDownlinePrice(settings) {
  const base = clampInt(settings?.price_per_gb || 0, 0, 1000000000);
  const markup = Math.max(1, clampInt(settings?.master_min_markup_toman || 100, 1, 1000000000));
  return base + markup;
}

function randomHex(bytes = 24) {
  const data = crypto.getRandomValues(new Uint8Array(bytes));
  return Array.from(data).map(x => x.toString(16).padStart(2, "0")).join("");
}

async function sha256Hex(value) {
  const digest = await crypto.subtle.digest("SHA-256", new TextEncoder().encode(String(value)));
  return bytesToHex(digest);
}

async function passwordHash(password, salt) {
  return sha256Hex(String(salt) + ":" + String(password));
}

const CENTRAL_WEB_COOKIE = "bp_central_session";

function webCookieSuffix(botId = "") {
  return String(botId || "default").replace(/[^a-zA-Z0-9_-]/g, "").slice(-36) || "default";
}

function salesWebCookieName(botId = "") {
  return "bp_sales_" + webCookieSuffix(botId);
}

function resellerAdminWebCookieName(botId = "") {
  return "bp_reseller_admin_" + webCookieSuffix(botId);
}

function webSessionCookieName(scope, botId = "") {
  if (scope === "central") return CENTRAL_WEB_COOKIE;
  if (scope === "reseller_admin") return resellerAdminWebCookieName(botId);
  return salesWebCookieName(botId);
}

function webAuthError(message = "برای ورود به نسخه وب احراز هویت کنید") {
  const error = new Error(message);
  error.code = "WEB_LOGIN_REQUIRED";
  return error;
}

function parseCookieHeader(request) {
  const out = {};
  const raw = request.headers.get("cookie") || "";
  for (const part of raw.split(";")) {
    const pos = part.indexOf("=");
    if (pos < 1) continue;
    const key = part.slice(0, pos).trim();
    const value = part.slice(pos + 1).trim();
    try { out[key] = decodeURIComponent(value); } catch (_) { out[key] = value; }
  }
  return out;
}

function webCookie(request, name, value, maxAgeSeconds) {
  const url = new URL(request.url);
  const secure = url.protocol === "https:" && !["localhost", "127.0.0.1", "::1"].includes(url.hostname);
  return name + "=" + encodeURIComponent(value) + "; Path=/; HttpOnly; SameSite=Lax; Max-Age=" + Math.max(0, Number(maxAgeSeconds || 0)) + (secure ? "; Secure" : "");
}

function clearWebCookie(request, name) {
  return webCookie(request, name, "", 0);
}

function requestIp(request) {
  return cleanText(request.headers.get("cf-connecting-ip") || request.headers.get("x-forwarded-for") || "", 120);
}

async function requestIpHash(request) {
  const ip = requestIp(request);
  return ip ? await sha256Hex("bluepanel:" + ip) : "";
}

async function issueWebSession(request, env, scope, subject = {}) {
  const settings = await getSettings(env);
  const days = clampInt(settings.web_session_days || 30, 1, 90);
  const seconds = days * 86400;
  const token = randomHex(32);
  const tokenHash = await sha256Hex(token);
  const ts = nowIso();
  const expiresAt = new Date(Date.now() + seconds * 1000).toISOString();
  await env.PASARGUARD_DB.prepare(`
    INSERT INTO web_sessions(token_hash,scope,user_id,customer_id,bot_id,expires_at,created_at,last_seen_at,user_agent,ip_hash)
    VALUES(?,?,?,?,?,?,?,?,?,?)
  `).bind(
    tokenHash,
    scope,
    subject.user_id || null,
    subject.customer_id || null,
    subject.bot_id || null,
    expiresAt,
    ts,
    ts,
    cleanText(request.headers.get("user-agent"), 300),
    await requestIpHash(request)
  ).run();
  await env.PASARGUARD_DB.prepare("DELETE FROM web_sessions WHERE expires_at<=?").bind(ts).run();
  return { token, tokenHash, expiresAt, seconds };
}

async function webSessionFromRequest(request, env, scope, botId = "") {
  const cookies = parseCookieHeader(request);
  const cookieName = webSessionCookieName(scope, botId);
  const token = cleanText(cookies[cookieName] || request.headers.get("x-web-session") || "", 200);
  if (!token) return null;
  const tokenHash = await sha256Hex(token);
  const row = await env.PASARGUARD_DB.prepare("SELECT * FROM web_sessions WHERE token_hash=? AND scope=?").bind(tokenHash, scope).first();
  if (!row) return null;
  if (botId && String(row.bot_id || "") !== String(botId)) return null;
  if (!row.expires_at || new Date(row.expires_at).getTime() <= Date.now()) {
    await env.PASARGUARD_DB.prepare("DELETE FROM web_sessions WHERE token_hash=?").bind(tokenHash).run();
    return null;
  }
  if (!row.last_seen_at || Date.now() - new Date(row.last_seen_at).getTime() > 300000) {
    await env.PASARGUARD_DB.prepare("UPDATE web_sessions SET last_seen_at=? WHERE token_hash=?").bind(nowIso(), tokenHash).run();
  }
  return row;
}

async function revokeWebSession(request, env, scope, botId = "") {
  const cookies = parseCookieHeader(request);
  const cookieName = webSessionCookieName(scope, botId);
  const token = cleanText(cookies[cookieName] || request.headers.get("x-web-session") || "", 200);
  if (token) await env.PASARGUARD_DB.prepare("DELETE FROM web_sessions WHERE token_hash=? AND scope=?").bind(await sha256Hex(token), scope).run();
  return cookieName;
}

async function fetchWithTimeout(url, options = {}, timeoutMs = 15000) {
  const controller = new AbortController();
  const timer = setTimeout(() => controller.abort("timeout"), Math.max(1000, Number(timeoutMs || 15000)));
  try {
    return await fetch(url, { ...options, signal: controller.signal });
  } finally {
    clearTimeout(timer);
  }
}

async function readJsonResponseSafe(response, sourceName = "سرور") {
  const raw = await response.text();
  if (!raw) return { data: {}, raw: "" };
  try {
    return { data: JSON.parse(raw), raw };
  } catch (_) {
    const clean = raw.replace(/<[^>]*>/g, " ").replace(/\s+/g, " ").trim().slice(0, 220);
    const error = new Error("پاسخ " + sourceName + " معتبر نیست (HTTP " + response.status + ")" + (clean ? ": " + clean : ""));
    error.code = "UPSTREAM_INVALID_RESPONSE";
    error.status = response.status;
    throw error;
  }
}

async function verifyPasarguardWebCredentials(env, username, password) {
  const settings = await getSettings(env);
  const baseUrl = pasarguardBaseUrl(settings);
  const form = new URLSearchParams();
  form.set("username", username);
  form.set("password", password);

  let response;
  try {
    response = await fetchWithTimeout(baseUrl + "/api/admin/token", {
      method: "POST",
      headers: {
        "content-type": "application/x-www-form-urlencoded",
        "accept": "application/json"
      },
      body: form.toString(),
      redirect: "manual"
    }, 18000);
  } catch (error) {
    if (String(error?.name || "").toLowerCase() === "aborterror" || String(error?.message || "").toLowerCase().includes("timeout")) {
      const timeoutError = new Error("پاسخ پنل PasarGuard طول کشید؛ اتصال پنل و آدرس آن را بررسی کنید");
      timeoutError.code = "PASARGUARD_TIMEOUT";
      throw timeoutError;
    }
    const networkError = new Error("ارتباط با پنل PasarGuard برقرار نشد: " + cleanText(error?.message || error, 180));
    networkError.code = "PASARGUARD_UNREACHABLE";
    throw networkError;
  }

  let parsed;
  try {
    parsed = await readJsonResponseSafe(response, "پنل PasarGuard");
  } catch (error) {
    error.code = error.code || "PASARGUARD_INVALID_RESPONSE";
    throw error;
  }
  const data = parsed.data || {};
  if (!response.ok || !data.access_token) {
    const authError = new Error(data.detail || data.error || "نام کاربری یا رمز پنل صحیح نیست");
    authError.code = response.status === 401 || response.status === 403 ? "INVALID_CREDENTIALS" : "PASARGUARD_AUTH_FAILED";
    authError.status = response.status;
    throw authError;
  }

  let profile = null;
  try {
    const profileResponse = await fetchWithTimeout(baseUrl + "/api/admin", {
      headers: {
        authorization: "Bearer " + String(data.access_token),
        accept: "application/json"
      },
      redirect: "manual"
    }, 12000);
    if (profileResponse.ok) {
      const profileParsed = await readJsonResponseSafe(profileResponse, "پروفایل PasarGuard");
      profile = profileParsed.data || null;
    }
  } catch (error) {
    console.error("pasarguard profile fetch error", error);
  }
  return { token: String(data.access_token), profile, settings };
}

function pasarguardProfileIdentity(rawProfile) {
  let profile = rawProfile && typeof rawProfile === "object" ? rawProfile : {};
  for (const key of ["admin", "user", "profile", "data", "result"]) {
    if (profile && profile[key] && typeof profile[key] === "object" && !Array.isArray(profile[key])) {
      const nested = profile[key];
      if (nested.id != null || nested.username != null || nested.telegram_id != null) {
        profile = nested;
        break;
      }
    }
  }
  return {
    raw: profile,
    id: profile?.id ?? profile?.admin_id ?? profile?.manager_id ?? null,
    username: cleanText(profile?.username || profile?.login || profile?.panel_username || "", 80),
    telegram_id: profile?.telegram_id ?? profile?.telegramId ?? null
  };
}

async function repairResellerManagementIdentity(env, bot, owner, identity, suppliedUsername) {
  if (!bot?.agency_id || String(bot.agency_id) === "shared-marzban") return bot;
  const remoteId = identity?.id != null ? String(identity.id) : "";
  const profileUsername = cleanText(identity?.username || suppliedUsername || "", 80);
  const storedRemote = bot.remote_manager_id != null ? String(bot.remote_manager_id) : "";
  const storedUsername = cleanText(bot.panel_username || "", 80);
  const ownerTelegram = owner?.telegram_id != null ? String(owner.telegram_id) : "";
  const profileTelegram = identity?.telegram_id != null ? String(identity.telegram_id) : "";
  const sameOwnerTelegram = ownerTelegram && profileTelegram && ownerTelegram === profileTelegram;
  const sameRemote = remoteId && storedRemote && remoteId === storedRemote;
  const sameStoredUsername = storedUsername && profileUsername && storedUsername.toLowerCase() === profileUsername.toLowerCase();

  if (!sameRemote && !sameStoredUsername && !sameOwnerTelegram) return bot;
  // Never silently overwrite a populated manager id with another id. Recovery is
  // intended for the null/legacy record produced by previous Marzban builds.
  const nextRemote = storedRemote || remoteId || null;
  const nextUsername = storedUsername || profileUsername || cleanText(suppliedUsername || "", 80);
  if ((!storedRemote && nextRemote) || (!storedUsername && nextUsername)) {
    await env.PASARGUARD_DB.prepare(`
      UPDATE agencies
      SET remote_manager_id=COALESCE(remote_manager_id,?),
          panel_username=CASE WHEN TRIM(COALESCE(panel_username,''))='' THEN ? ELSE panel_username END,
          runtime_version=?,update_applied_at=?,updated_at=?
      WHERE id=? AND user_id=?
    `).bind(nextRemote, nextUsername, APP_VERSION, nowIso(), nowIso(), bot.agency_id, owner.id).run();
    return { ...bot, remote_manager_id: nextRemote, panel_username: nextUsername };
  }
  return bot;
}

async function findSalesWebCustomer(env, botId, identifier) {
  const value = cleanText(identifier, 100).replace(/^@/, "");
  if (!value) return null;
  if (/^\d+$/.test(value)) return env.PASARGUARD_DB.prepare("SELECT * FROM sales_customers WHERE bot_id=? AND telegram_id=? AND status='active'").bind(botId, value).first();
  const rows = await env.PASARGUARD_DB.prepare("SELECT * FROM sales_customers WHERE bot_id=? AND LOWER(username)=LOWER(?) AND status='active' ORDER BY updated_at DESC LIMIT 2").bind(botId, value).all();
  if ((rows.results || []).length !== 1) return null;
  return rows.results[0];
}

async function salesWebRequestCode(request, env, botId) {
  await ensureDb(env);
  const bot = await getResellerBotById(env, botId);
  if (!bot || Number(bot.miniapp_enabled ?? 1) !== 1) return fail("فروشگاه پیدا نشد", 404, "NOT_FOUND");
  if (bot.status !== "active") return fail("فروش این ربات موقتاً متوقف است", 403, "BOT_INACTIVE");
  try { resellerRequireActiveLicense(bot); } catch (error) { return fail(error.message, 403, error.code || "LICENSE_EXPIRED"); }
  const body = await parseBody(request);
  const identifier = cleanText(body.identifier, 100);
  const customer = await findSalesWebCustomer(env, bot.id, identifier);
  if (!customer) return fail("حساب پیدا نشد؛ ابتدا یک‌بار ربات نماینده را Start کنید و سپس دوباره تلاش کنید", 404, "CUSTOMER_NOT_FOUND");

  const latest = await env.PASARGUARD_DB.prepare("SELECT * FROM web_login_codes WHERE scope='sales' AND bot_id=? AND customer_id=? AND consumed_at IS NULL ORDER BY created_at DESC LIMIT 1").bind(bot.id, customer.id).first();
  if (latest && Date.now() - new Date(latest.created_at).getTime() < 60000) return fail("برای درخواست کد جدید یک دقیقه صبر کنید", 429, "OTP_COOLDOWN");

  const settings = await getSettings(env);
  const minutes = clampInt(settings.sales_web_otp_minutes || 10, 3, 30);
  const bytes = crypto.getRandomValues(new Uint32Array(1))[0];
  const code = String(bytes % 1000000).padStart(6, "0");
  const salt = randomHex(16);
  const codeHash = await passwordHash(code, salt + ":" + bot.id + ":" + customer.id);
  const rowId = id("otp");
  const ts = nowIso();
  const expiresAt = new Date(Date.now() + minutes * 60000).toISOString();
  await env.PASARGUARD_DB.prepare("INSERT INTO web_login_codes(id,scope,bot_id,customer_id,code_hash,code_salt,attempts,expires_at,created_at) VALUES(?,'sales',?,?,?,?,0,?,?)")
    .bind(rowId, bot.id, customer.id, codeHash, salt, expiresAt, ts).run();
  try {
    await resellerTelegramApi(env, bot, "sendMessage", {
      chat_id: customer.telegram_id,
      text: "🔐 <b>کد ورود نسخه وب " + botEscape(bot.brand_name || "BluePanel") + "</b>\n\nکد ورود: <code>" + code + "</code>\nاعتبار: <b>" + minutes + " دقیقه</b>\n\nاین کد را در اختیار دیگران قرار ندهید.",
      parse_mode: "HTML"
    });
  } catch (error) {
    await env.PASARGUARD_DB.prepare("DELETE FROM web_login_codes WHERE id=?").bind(rowId).run();
    return fail("ارسال کد در تلگرام ناموفق بود؛ ابتدا ربات را Start کنید", 400, "OTP_SEND_FAILED");
  }
  return json({ success: true, message: "کد ورود در تلگرام ارسال شد", expires_at: expiresAt, destination: customer.username ? "@" + customer.username : String(customer.telegram_id).slice(0, 3) + "***" });
}

async function salesWebVerifyCode(request, env, botId) {
  await ensureDb(env);
  const bot = await getResellerBotById(env, botId);
  if (!bot || Number(bot.miniapp_enabled ?? 1) !== 1) return fail("فروشگاه پیدا نشد", 404, "NOT_FOUND");
  try { resellerRequireActiveLicense(bot); } catch (error) { return fail(error.message, 403, error.code || "LICENSE_EXPIRED"); }
  const body = await parseBody(request);
  const customer = await findSalesWebCustomer(env, bot.id, body.identifier);
  const code = cleanText(body.code, 12).replace(/\D/g, "");
  if (!customer || code.length !== 6) return fail("شناسه یا کد ورود صحیح نیست", 400, "OTP_INVALID");
  const row = await env.PASARGUARD_DB.prepare("SELECT * FROM web_login_codes WHERE scope='sales' AND bot_id=? AND customer_id=? AND consumed_at IS NULL ORDER BY created_at DESC LIMIT 1").bind(bot.id, customer.id).first();
  if (!row || new Date(row.expires_at).getTime() <= Date.now()) return fail("کد منقضی شده است؛ کد جدید دریافت کنید", 400, "OTP_EXPIRED");
  if (Number(row.attempts || 0) >= 5) return fail("تعداد تلاش بیش از حد مجاز است؛ کد جدید دریافت کنید", 429, "OTP_LOCKED");
  const computed = await passwordHash(code, row.code_salt + ":" + bot.id + ":" + customer.id);
  if (!timingSafeEqualHex(computed, row.code_hash)) {
    await env.PASARGUARD_DB.prepare("UPDATE web_login_codes SET attempts=attempts+1 WHERE id=?").bind(row.id).run();
    return fail("کد ورود صحیح نیست", 400, "OTP_INVALID");
  }
  await env.PASARGUARD_DB.prepare("UPDATE web_login_codes SET consumed_at=? WHERE id=?").bind(nowIso(), row.id).run();
  const session = await issueWebSession(request, env, "sales", { bot_id: bot.id, customer_id: customer.id });
  await salesEvent(env, bot.id, customer.id, "web_login", { mode: "telegram_otp" });
  return json({ success: true, message: "ورود موفق بود", expires_at: session.expiresAt }, 200, {
    "set-cookie": webCookie(request, salesWebCookieName(bot.id), session.token, session.seconds)
  });
}

async function salesWebLogout(request, env, botId) {
  await ensureDb(env);
  const cookieName = await revokeWebSession(request, env, "sales", botId);
  return json({ success: true, message: "از نسخه وب خارج شدید" }, 200, { "set-cookie": clearWebCookie(request, cookieName) });
}

function bytesToHex(bytes) {
  return Array.from(new Uint8Array(bytes)).map(b => b.toString(16).padStart(2, "0")).join("");
}

function timingSafeEqualHex(a, b) {
  if (a.length !== b.length) return false;
  let diff = 0;
  for (let i = 0; i < a.length; i++) diff |= a.charCodeAt(i) ^ b.charCodeAt(i);
  return diff === 0;
}

async function hmacSha256(keyBytes, message) {
  const key = await crypto.subtle.importKey(
    "raw",
    keyBytes,
    { name: "HMAC", hash: "SHA-256" },
    false,
    ["sign"]
  );
  return crypto.subtle.sign("HMAC", key, new TextEncoder().encode(message));
}

async function validateTelegramInitData(initData, botToken, maxAgeSeconds = 86400) {
  if (!initData || !botToken) throw new Error("Telegram authentication is not configured");
  const params = new URLSearchParams(initData);
  const receivedHash = params.get("hash") || "";
  params.delete("hash");
  const dataCheckString = Array.from(params.entries())
    .sort(([a], [b]) => a.localeCompare(b))
    .map(([key, value]) => key + "=" + value)
    .join("\n");

  const secret = await hmacSha256(new TextEncoder().encode("WebAppData"), botToken);
  const computed = bytesToHex(await hmacSha256(new Uint8Array(secret), dataCheckString));
  if (!timingSafeEqualHex(computed, receivedHash)) throw new Error("Invalid Telegram signature");

  const authDate = Number(params.get("auth_date") || 0);
  const age = Math.floor(Date.now() / 1000) - authDate;
  if (!authDate || age < -60 || age > maxAgeSeconds) throw new Error("Telegram session has expired");

  const userRaw = params.get("user");
  if (!userRaw) throw new Error("Telegram user is missing");
  return JSON.parse(userRaw);
}

function isAdminTelegramId(settings, telegramId) {
  const ids = String(settings.admin_ids || "").split(",").map(x => x.trim()).filter(Boolean);
  return ids.includes(String(telegramId));
}

async function audit(env, actorUserId, action, details = {}) {
  await env.PASARGUARD_DB.prepare("INSERT INTO audit_logs(id, actor_user_id, action, details, created_at) VALUES(?, ?, ?, ?, ?)")
    .bind(id("log"), actorUserId || null, action, JSON.stringify(details), nowIso()).run();
}

function resellerStaffRoleLabel(role) {
  if (role === "owner") return "مالک";
  return RESELLER_STAFF_ROLES[String(role || "")]?.label || "اپراتور";
}

function resellerManagerHas(account, permission) {
  if (!permission) return true;
  const actor = account?.resellerActor || {};
  if (actor.role === "owner") return true;
  if (permission === "owner") return false;
  return Array.isArray(actor.permissions) && actor.permissions.includes(permission);
}

function resellerRequirePermission(account, permission) {
  if (!resellerManagerHas(account, permission)) {
    const error = new Error("برای این عملیات دسترسی کافی ندارید");
    error.code = "RESELLER_PERMISSION_DENIED";
    throw error;
  }
}

function resellerViewPermission(view) {
  return ({
    home: "dashboard", group_overview: "dashboard", group_sales: "dashboard",
    group_content: "dashboard", group_finance: "dashboard", group_communications: "dashboard", group_system: "dashboard",
    plans: "plans", orders: "orders", services: "orders", service: "orders", catalog: "catalog",
    wallets: "wallets", stats: "stats", users: "users", user: "users",
    texts: "texts", promos: "promos", tickets: "tickets", ticket: "tickets",
    settings: "settings", settings_identity: "settings", settings_loyalty: "settings",
    settings_support: "settings", settings_automation: "settings",
    payments: "settings", payment_methods: "settings", plisio: "settings", campaigns: "campaigns", staff: "owner", audit: "audit", children: "owner",
    executive: "reports", automation: "automation", security: "security", health: "health", backups: "backups"
  })[String(view || "home")] || "dashboard";
}

function resellerCallbackPermission(data) {
  const value = String(data || "");
  if (value.startsWith("owner:staff") || value.startsWith("owner:child") || value === "owner:children" || value === "owner:token") return "owner";
  if (value.startsWith("owner:campaign") || value.startsWith("owner:broadcast")) return "campaigns";
  if (value.startsWith("owner:audit")) return "audit";
  if (value.startsWith("owner:executive")) return "reports";
  if (value.startsWith("owner:automation") || value.startsWith("owner:growth")) return "automation";
  if (value.startsWith("owner:security")) return "security";
  if (value.startsWith("owner:health")) return "health";
  if (value.startsWith("owner:backup")) return "backups";
  if (value.startsWith("owner:ticket")) return "tickets";
  if (value.startsWith("owner:approve") || value.startsWith("owner:reject") || value.startsWith("owner:receipt") || value.startsWith("owner:orders") || value.startsWith("owner:services") || value.startsWith("osv:")) return "orders";
  if (value.startsWith("owner:wallet")) return "wallets";
  if (value.startsWith("owner:user")) return "users";
  if (value.startsWith("owner:promo")) return "promos";
  if (value.startsWith("owner:text")) return "texts";
  if (value.startsWith("owner:plan")) return "plans";
  if (value.startsWith("owner:category") || value.startsWith("owner:location") || value.startsWith("owner:catalog")) return "catalog";
  if (value.startsWith("owner:payment") || value.startsWith("owner:methods") || value.startsWith("owner:plisio") || value.startsWith("owner:cubepay") || value === "owner:payments" || value === "owner:payment_methods") return "settings";
  if (value.startsWith("owner:setting") || value === "owner:card" || value === "owner:panel" || value.startsWith("owner:agency") || value === "owner:toggle") return "settings";
  if (value === "owner:stats") return "stats";
  if (value === "owner:users") return "users";
  if (value === "owner:plans") return "plans";
  if (value === "owner:promos") return "promos";
  if (value === "owner:texts") return "texts";
  if (value === "owner:tickets") return "tickets";
  if (value === "owner:wallets") return "wallets";
  if (value === "owner:settings") return "settings";
  return "dashboard";
}

function resellerSessionPermission(state) {
  const value = String(state || "");
  if (value.startsWith("owner_staff") || value.startsWith("owner_child") || value === "owner_bot_token") return "owner";
  if (value.startsWith("owner_campaign") || value === "owner_broadcast") return "campaigns";
  if (value.startsWith("owner_ticket")) return "tickets";
  if (value.startsWith("owner_user")) return "users";
  if (value.startsWith("owner_promo")) return "promos";
  if (value.startsWith("owner_text")) return "texts";
  if (value.startsWith("owner_plan")) return "plans";
  if (value.startsWith("owner_category") || value.startsWith("owner_location")) return "catalog";
  return "settings";
}

async function resellerAudit(env, bot, account, action, details = {}) {
  const actor = account?.resellerActor || {};
  const telegramId = String(actor.telegram_id || account?.user?.telegram_id || bot?.owner_telegram_id || "0");
  await env.PASARGUARD_DB.prepare(`
    INSERT INTO reseller_audit_logs(id,bot_id,actor_telegram_id,actor_role,action,details,created_at)
    VALUES(?,?,?,?,?,?,?)
  `).bind(id("ral"), bot.id, telegramId, String(actor.role || "owner"), cleanText(action, 120), JSON.stringify(details || {}), nowIso()).run();
}

function resellerCampaignTargetLabel(scope) {
  return RESELLER_CAMPAIGN_TARGETS[String(scope || "all")] || RESELLER_CAMPAIGN_TARGETS.all;
}

function resellerCampaignStatusLabel(status) {
  return ({ pending: "زمان‌بندی‌شده", running: "در حال ارسال", completed: "تکمیل‌شده", cancelled: "لغوشده", failed: "ناموفق" })[String(status || "")] || String(status || "نامشخص");
}

function arrayBufferToBase64(buffer) {
  let binary = "";
  for (const byte of new Uint8Array(buffer)) binary += String.fromCharCode(byte);
  return btoa(binary);
}

function base64ToBytes(text) {
  const binary = atob(text);
  const bytes = new Uint8Array(binary.length);
  for (let i = 0; i < binary.length; i++) bytes[i] = binary.charCodeAt(i);
  return bytes;
}

async function encryptionKey(env) {
  const settings = await getSettings(env);
  const source = String(settings.app_encryption_key || settings.bot_token || "change-me");
  if (encryptionKeyCache && encryptionKeyCacheSource === source) return encryptionKeyCache;
  const digest = await crypto.subtle.digest("SHA-256", new TextEncoder().encode(source));
  encryptionKeyCache = await crypto.subtle.importKey("raw", digest, { name: "AES-GCM" }, false, ["encrypt", "decrypt"]);
  encryptionKeyCacheSource = source;
  return encryptionKeyCache;
}

async function encryptSecret(value, env) {
  const iv = crypto.getRandomValues(new Uint8Array(12));
  const key = await encryptionKey(env);
  const encrypted = await crypto.subtle.encrypt({ name: "AES-GCM", iv }, key, new TextEncoder().encode(value));
  return arrayBufferToBase64(iv) + "." + arrayBufferToBase64(encrypted);
}

async function decryptSecret(value, env) {
  if (!value || !value.includes(".")) return "";
  const [ivB64, dataB64] = value.split(".");
  const key = await encryptionKey(env);
  const decrypted = await crypto.subtle.decrypt(
    { name: "AES-GCM", iv: base64ToBytes(ivB64) },
    key,
    base64ToBytes(dataB64)
  );
  return new TextDecoder().decode(decrypted);
}


let telegramReplyRouteSchemaReady = false;

async function ensureTelegramReplyRouteSchema(env) {
  if (telegramReplyRouteSchemaReady) return;
  await env.PASARGUARD_DB.prepare(`
    CREATE TABLE IF NOT EXISTS telegram_reply_routes (
      bot_scope TEXT NOT NULL,
      chat_id TEXT NOT NULL,
      button_text TEXT NOT NULL,
      action_json TEXT NOT NULL,
      source_message_id INTEGER,
      expires_at TEXT NOT NULL,
      updated_at TEXT NOT NULL,
      PRIMARY KEY(bot_scope, chat_id, button_text)
    )
  `).run();
  await env.PASARGUARD_DB.prepare(`
    CREATE INDEX IF NOT EXISTS idx_telegram_reply_routes_expiry
    ON telegram_reply_routes(expires_at)
  `).run();
  telegramReplyRouteSchemaReady = true;
}

function telegramReplyButtonText(value, fallback, seen) {
  let text = String(value || fallback || "گزینه").replace(/\s+/g, " ").trim();
  if (!text) text = "گزینه";
  if (text.length > 56) text = text.slice(0, 53) + "…";
  const base = text;
  let counter = 2;
  while (seen.has(text)) {
    const suffix = " · " + counter++;
    text = base.slice(0, Math.max(1, 64 - suffix.length)) + suffix;
  }
  seen.add(text);
  return text;
}

function telegramReplyKeyboardPlan(inlineKeyboard) {
  const rows = [];
  const routes = [];
  const seen = new Set();
  let ordinal = 0;
  for (const sourceRow of Array.isArray(inlineKeyboard) ? inlineKeyboard : []) {
    const row = [];
    for (const button of Array.isArray(sourceRow) ? sourceRow : []) {
      ordinal += 1;
      const text = telegramReplyButtonText(button?.text, "گزینه " + ordinal, seen);
      if (button?.web_app?.url) {
        row.push({ text, web_app: { url: String(button.web_app.url) } });
        continue;
      }
      row.push({ text });
      let action = null;
      if (button?.callback_data) action = { kind: "callback", data: String(button.callback_data) };
      else if (button?.url) action = { kind: "url", value: String(button.url) };
      else if (button?.copy_text?.text != null) action = { kind: "copy", value: String(button.copy_text.text) };
      else if (button?.switch_inline_query != null) action = { kind: "text", value: String(button.switch_inline_query || "") };
      else if (button?.switch_inline_query_current_chat != null) action = { kind: "text", value: String(button.switch_inline_query_current_chat || "") };
      else if (button?.login_url?.url) action = { kind: "url", value: String(button.login_url.url) };
      if (action) routes.push({ text, action });
    }
    if (row.length) rows.push(row);
  }
  return {
    markup: {
      keyboard: rows,
      resize_keyboard: true,
      is_persistent: true,
      one_time_keyboard: false,
      input_field_placeholder: "یک گزینه را از منوی پایین انتخاب کنید"
    },
    routes
  };
}

async function telegramReplaceReplyRoutes(env, botScope, chatId, routes, sourceMessageId = null) {
  if (!env?.PASARGUARD_DB || chatId == null) return;
  await ensureTelegramReplyRouteSchema(env);
  const scope = String(botScope || "central");
  const chat = String(chatId);
  const now = nowIso();
  const expires = new Date(Date.now() + 7 * 24 * 60 * 60 * 1000).toISOString();
  const statements = [
    env.PASARGUARD_DB.prepare("DELETE FROM telegram_reply_routes WHERE bot_scope=? AND chat_id=?").bind(scope, chat)
  ];
  for (const route of routes || []) {
    statements.push(env.PASARGUARD_DB.prepare(`
      INSERT INTO telegram_reply_routes(bot_scope,chat_id,button_text,action_json,source_message_id,expires_at,updated_at)
      VALUES(?,?,?,?,?,?,?)
      ON CONFLICT(bot_scope,chat_id,button_text) DO UPDATE SET
        action_json=excluded.action_json,
        source_message_id=excluded.source_message_id,
        expires_at=excluded.expires_at,
        updated_at=excluded.updated_at
    `).bind(scope, chat, String(route.text), JSON.stringify(route.action || {}), sourceMessageId == null ? null : Number(sourceMessageId), expires, now));
  }
  await env.PASARGUARD_DB.batch(statements);
}

async function telegramFindReplyRoute(env, botScope, chatId, buttonText) {
  if (!env?.PASARGUARD_DB || chatId == null || !buttonText) return null;
  await ensureTelegramReplyRouteSchema(env);
  const row = await env.PASARGUARD_DB.prepare(`
    SELECT action_json,source_message_id FROM telegram_reply_routes
    WHERE bot_scope=? AND chat_id=? AND button_text=? AND expires_at>?
    LIMIT 1
  `).bind(String(botScope || "central"), String(chatId), String(buttonText), nowIso()).first();
  if (!row) return null;
  let action = {};
  try { action = JSON.parse(row.action_json || "{}"); } catch (_) {}
  return { action, source_message_id: row.source_message_id == null ? null : Number(row.source_message_id) };
}

async function telegramSendReplyRouteSpecial(sendFn, chatId, route) {
  const action = route?.action || {};
  if (action.kind === "url") {
    await sendFn("sendMessage", { chat_id: chatId, text: "🔗 لینک موردنظر:\n" + String(action.value || ""), disable_web_page_preview: true });
    return true;
  }
  if (action.kind === "copy") {
    const value = String(action.value || "");
    const escaped = typeof botEscape === "function" ? botEscape(value) : value.replace(/[&<>]/g, ch => ({"&":"&amp;","<":"&lt;",">":"&gt;"}[ch]));
    await sendFn("sendMessage", { chat_id: chatId, text: "📋 برای کپی روی متن زیر بزنید:\n<code>" + escaped + "</code>", parse_mode: "HTML" });
    return true;
  }
  if (action.kind === "text") {
    await sendFn("sendMessage", { chat_id: chatId, text: String(action.value || "") || "این گزینه ورودی متنی ندارد." });
    return true;
  }
  return false;
}

async function telegramUiApi(env, botScope, token, method, body) {
  const payload = { ...(body || {}) };
  if (method === "answerCallbackQuery" && String(payload.callback_query_id || "").startsWith("reply-keyboard-")) {
    return { ok: true, result: true };
  }
  const inlineKeyboard = payload?.reply_markup?.inline_keyboard;
  const chatId = payload.chat_id;
  if (!Array.isArray(inlineKeyboard)) {
    const result = await telegramApiWithToken(token, method, payload);
    if (chatId != null && (payload?.reply_markup?.keyboard || payload?.reply_markup?.remove_keyboard)) {
      await telegramReplaceReplyRoutes(env, botScope, chatId, [], result?.result?.message_id || null);
    }
    return result;
  }


  if (!inlineKeyboard.length || !inlineKeyboard.some(row => Array.isArray(row) && row.length)) {
    if (chatId != null) await telegramReplaceReplyRoutes(env, botScope, chatId, [], null);
    if (method === "editMessageReplyMarkup") return { ok: true, result: true };
    return telegramApiWithToken(token, method, payload);
  }

  const plan = telegramReplyKeyboardPlan(inlineKeyboard);
  if (!plan.markup.keyboard.length) {
    if (chatId != null) await telegramReplaceReplyRoutes(env, botScope, chatId, [], null);
    const without = { ...payload };
    delete without.reply_markup;
    return telegramApiWithToken(token, method, without);
  }

  if (method === "editMessageText" || method === "editMessageCaption") {
    const editPayload = { ...payload };
    delete editPayload.reply_markup;
    let edited = null;
    try { edited = await telegramApiWithToken(token, method, editPayload); }
    catch (error) {
      if (!/message is not modified/i.test(String(error?.message || error))) throw error;
    }
    const prompt = await telegramApiWithToken(token, "sendMessage", {
      chat_id: chatId,
      text: "⌨️ گزینه موردنظر را از منوی پایین انتخاب کنید.",
      reply_markup: plan.markup
    });
    await telegramReplaceReplyRoutes(env, botScope, chatId, plan.routes, prompt?.result?.message_id || null);
    return edited || prompt;
  }

  if (method === "editMessageReplyMarkup") {
    await telegramReplaceReplyRoutes(env, botScope, chatId, plan.routes, payload.message_id || null);
    const prompt = await telegramApiWithToken(token, "sendMessage", {
      chat_id: chatId,
      text: "⌨️ گزینه موردنظر را از منوی پایین انتخاب کنید.",
      reply_markup: plan.markup
    });
    await telegramReplaceReplyRoutes(env, botScope, chatId, plan.routes, prompt?.result?.message_id || null);
    return prompt;
  }

  payload.reply_markup = plan.markup;
  const result = await telegramApiWithToken(token, method, payload);
  await telegramReplaceReplyRoutes(env, botScope, chatId, plan.routes, result?.result?.message_id || null);
  return result;
}

