  const title = SALES_TEXT_LABELS[key] || "راهنما";
  const text = await salesBotText(env, bot.id, key, SALES_TEXT_DEFAULTS[key] || "راهنمایی ثبت نشده است.");
  return {
    text: "📘 <b>" + botEscape(title) + "</b>\n━━━━━━━━━━━━━━\n" + botEscape(text),
    reply_markup: { inline_keyboard: [[{ text: "↩️ مرکز آموزش", callback_data: "sale:help" }, { text: "🏠 منوی اصلی", callback_data: "sale:home" }]] }
  };
