async function sendSalesReferralView(env, bot, customer, chatId) {
  const rendered = await salesCustomerReferralView(env, bot, customer);
  if (bot.referral_banner_file_id) {
    const method = String(bot.referral_banner_file_type || "photo") === "document" ? "sendDocument" : "sendPhoto";
    const key = method === "sendDocument" ? "document" : "photo";
    const payload = { chat_id: chatId, caption: rendered.text, parse_mode: "HTML", reply_markup: rendered.reply_markup, protect_content: Number(bot.forward_enabled ?? 1) !== 1 };
    payload[key] = bot.referral_banner_file_id;
    try { return await resellerTelegramApi(env, bot, method, payload); } catch (_) {}
  }
  return resellerTelegramApi(env, bot, "sendMessage", { chat_id: chatId, text: rendered.text, parse_mode: "HTML", reply_markup: rendered.reply_markup, disable_web_page_preview: true, protect_content: Number(bot.forward_enabled ?? 1) !== 1 });
}

async function salesCustomerSendOrEdit(env, bot, target, view, options = {}) {
  let rendered;
  if (view === "group_services") rendered = await salesCustomerGroupView(env, bot, target.customer, "services");
  else if (view === "group_account") rendered = await salesCustomerGroupView(env, bot, target.customer, "account");
  else if (view === "group_rewards") rendered = await salesCustomerGroupView(env, bot, target.customer, "rewards");
  else if (view === "group_support") rendered = await salesCustomerGroupView(env, bot, target.customer, "support");
  else if (view === "plans") rendered = await salesCustomerPlansView(env, bot, target.customer, options);
  else if (view === "categories") rendered = await salesCustomerCategoriesView(env, bot, options);
  else if (view === "locations") {
    const locations = await salesActivePurchaseLocations(env, bot);
    if (locations.length === 1) {
      const locationId = String(locations[0].id);
      const previous = await salesSessionGet(env, bot.id, target.customer.telegram_id);
      await salesSessionSet(env, bot.id, target.customer.telegram_id, "purchase_location", {
        ...(previous?.data || {}), locationId, singleLocation: true
      });
      rendered = await salesCustomerCategoriesView(env, bot, { locationId, singleLocation: true });
    } else {
      rendered = await salesCustomerLocationsView(env, bot);
    }
  }
  else if (view === "orders") rendered = await salesCustomerOrdersView(env, bot, target.customer);
  else if (view === "order_detail") rendered = await salesCustomerOrderDetailView(env, bot, target.customer, options.orderId);
  else if (view === "services") rendered = await salesCustomerServicesView(env, bot, target.customer);
  else if (view === "service_detail") rendered = await salesCustomerServiceDetailView(env, bot, target.customer, options.serviceId);
  else if (view === "wallet") rendered = await salesCustomerWalletView(env, bot, target.customer);
  else if (view === "account") rendered = await salesCustomerAccountView(env, bot, target.customer);
  else if (view === "referral") rendered = await salesCustomerReferralView(env, bot, target.customer);
  else if (view === "promo") rendered = await salesCustomerPromoView(env, bot, target.customer);
  else if (view === "help") rendered = await salesCustomerHelpView(env, bot);
  else if (view === "help_article") rendered = await salesCustomerHelpArticleView(env, bot, options.key);
  else rendered = await salesCustomerHomeView(env, bot, target.customer);
  const payload = {
    chat_id: target.chatId,
    text: rendered.text,
    parse_mode: "HTML",
    disable_web_page_preview: true,
    protect_content: Number(bot.forward_enabled ?? 1) !== 1,
    reply_markup: rendered.reply_markup
  };
  if (target.messageId) {
    try {
      await resellerTelegramApi(env, bot, "editMessageText", { ...payload, message_id: target.messageId });
      return;
    } catch (error) {
      if (String(error.message || "").toLowerCase().includes("message is not modified")) return;
    }
  }
  await resellerTelegramApi(env, bot, "sendMessage", payload);
}

function resellerSecurityConfig(bot) {
  return {
    enabled: Number(bot?.fraud_protection_enabled ?? 1) === 1,
    cooldownSeconds: Math.max(0, Math.min(3600, Number(bot?.order_cooldown_seconds || 30))),
    maxPendingOrders: Math.max(1, Math.min(50, Number(bot?.max_pending_orders || 3))),
    dailyOrderLimit: Math.max(1, Math.min(500, Number(bot?.daily_order_limit || 10))),
    dailyWalletLimit: Math.max(0, Math.min(1000000000000, Number(bot?.daily_wallet_charge_limit_toman || 5000000))),
    duplicateReceiptProtection: Number(bot?.duplicate_receipt_protection ?? 1) === 1,
    autoBlockRiskScore: Math.max(0, Math.min(1000, Number(bot?.auto_block_risk_score || 100)))
  };
}

function salesRiskLevel(score) {
  const value = Number(score || 0);
  if (value >= 100) return "critical";
  if (value >= 60) return "high";
  if (value >= 25) return "medium";
  return "normal";
}

async function recordSalesSecurityEvent(env, bot, customer, eventType, severity = "info", scoreDelta = 0, details = {}) {
  const ts = nowIso();
  const customerId = customer?.id || null;
  await env.PASARGUARD_DB.prepare(`
    INSERT INTO sales_security_events(id,bot_id,customer_id,event_type,severity,score_delta,details,created_at)
    VALUES(?,?,?,?,?,?,?,?)
  `).bind(id("sec"), bot.id, customerId, cleanText(eventType, 120), cleanText(severity, 20),
    Number(scoreDelta || 0), JSON.stringify(details || {}), ts).run();
  if (!customerId || !Number(scoreDelta || 0)) return { score: Number(customer?.risk_score || 0), blocked: false };
  const freshBefore = await env.PASARGUARD_DB.prepare("SELECT risk_score,status FROM sales_customers WHERE id=? AND bot_id=?")
    .bind(customerId, bot.id).first();
  const nextScore = Math.max(0, Number(freshBefore?.risk_score || 0) + Number(scoreDelta || 0));
  const level = salesRiskLevel(nextScore);
  const threshold = resellerSecurityConfig(bot).autoBlockRiskScore;
  const shouldBlock = threshold > 0 && nextScore >= threshold;
  await env.PASARGUARD_DB.prepare(`
    UPDATE sales_customers SET risk_score=?,risk_level=?,last_security_event_at=?,
      status=CASE WHEN ?=1 THEN 'blocked' ELSE status END,updated_at=? WHERE id=? AND bot_id=?
  `).bind(nextScore, level, ts, shouldBlock ? 1 : 0, ts, customerId, bot.id).run();
  if (shouldBlock && String(freshBefore?.status || "") !== "blocked") {
    try {
      await resellerTelegramApi(env, bot, "sendMessage", {
        chat_id: bot.owner_telegram_id,
        text: "🚨 <b>مسدودسازی خودکار کاربر پرخطر</b>\nکاربر: <code>" + botEscape(customer.telegram_id || customerId) +
          "</code>\nامتیاز ریسک: <b>" + botMoney(nextScore) + "</b>\nرخداد: <b>" + botEscape(eventType) + "</b>",
        parse_mode: "HTML"
      });
    } catch (_) {}
  }
  return { score: nextScore, blocked: shouldBlock };
}

function salesSecurityError(message, code = "SECURITY_LIMIT") {
  const error = new Error(message);
  error.code = code;
  return error;
}

async function enforceSalesSecurity(env, bot, customer, action, amountToman = 0) {
  const cfg = resellerSecurityConfig(bot);
  if (String(customer?.status || "active") !== "active") {
    throw salesSecurityError("حساب شما برای انجام عملیات جدید محدود شده است. با پشتیبانی تماس بگیرید.", "CUSTOMER_BLOCKED");
  }
  if (!cfg.enabled) return cfg;
  const now = Date.now();
  const today = new Date();
  today.setUTCHours(0, 0, 0, 0);
  const dayStart = today.toISOString();
  const actionType = cleanText(action, 50);

  if (cfg.cooldownSeconds > 0) {
    const last = await env.PASARGUARD_DB.prepare(`
      SELECT created_at FROM sales_bot_events WHERE bot_id=? AND customer_id=? AND event_type=? ORDER BY created_at DESC LIMIT 1
    `).bind(bot.id, customer.id, "security_action:" + actionType).first();
    if (last?.created_at) {
      const wait = cfg.cooldownSeconds - Math.floor((now - Date.parse(last.created_at)) / 1000);
      if (wait > 0) {
        await recordSalesSecurityEvent(env, bot, customer, "rapid_action", "warning", 5, { action: actionType, wait });
        throw salesSecurityError("لطفاً " + wait + " ثانیه صبر کنید و دوباره تلاش کنید.", "ACTION_COOLDOWN");
      }
    }
  }

  if (["order", "renewal", "volume"].includes(actionType)) {
    const row = await env.PASARGUARD_DB.prepare(`
      SELECT
        (SELECT COUNT(*) FROM sales_orders WHERE bot_id=? AND customer_id=? AND status IN ('awaiting_receipt','payment_pending','receipt_uploading','pending_review','processing','provisioning')) AS pending_count,
        (SELECT COUNT(*) FROM sales_orders WHERE bot_id=? AND customer_id=? AND created_at>=?) AS daily_count
    `).bind(bot.id, customer.id, bot.id, customer.id, dayStart).first();
    if (Number(row?.pending_count || 0) >= cfg.maxPendingOrders) {
      await recordSalesSecurityEvent(env, bot, customer, "pending_order_limit", "warning", 10, { count: row.pending_count, limit: cfg.maxPendingOrders });
      throw salesSecurityError("تعداد سفارش‌های در انتظار شما به حد مجاز رسیده است.", "PENDING_ORDER_LIMIT");
    }
    if (Number(row?.daily_count || 0) >= cfg.dailyOrderLimit) {
      await recordSalesSecurityEvent(env, bot, customer, "daily_order_limit", "high", 15, { count: row.daily_count, limit: cfg.dailyOrderLimit });
      throw salesSecurityError("سقف تعداد سفارش روزانه شما تکمیل شده است.", "DAILY_ORDER_LIMIT");
    }
  }

  if (actionType === "wallet_charge" && cfg.dailyWalletLimit > 0) {
    const row = await env.PASARGUARD_DB.prepare(`
      SELECT COALESCE(SUM(amount_toman),0) AS total FROM sales_wallet_requests
      WHERE bot_id=? AND customer_id=? AND created_at>=? AND status NOT IN ('rejected','cancelled')
    `).bind(bot.id, customer.id, dayStart).first();
    if (Number(row?.total || 0) + Number(amountToman || 0) > cfg.dailyWalletLimit) {
      await recordSalesSecurityEvent(env, bot, customer, "daily_wallet_limit", "high", 20, { current: row?.total || 0, requested: amountToman, limit: cfg.dailyWalletLimit });
      throw salesSecurityError("مبلغ شارژ از سقف مجاز روزانه بیشتر است.", "DAILY_WALLET_LIMIT");
    }
  }

  await salesEvent(env, bot.id, customer.id, "security_action:" + actionType, { amountToman: Number(amountToman || 0) });
  return cfg;
}

async function salesReceiptFingerprint(bytes) {
  const digest = await crypto.subtle.digest("SHA-256", bytes);
  return "sha256:" + Array.from(new Uint8Array(digest)).map(x => x.toString(16).padStart(2, "0")).join("");
}

async function ensureUniqueSalesReceipt(env, bot, customer, fingerprint, currentType, currentId) {
  const cfg = resellerSecurityConfig(bot);
  const value = cleanText(fingerprint, 200);
  if (!cfg.enabled || !cfg.duplicateReceiptProtection || !value) return;
  const duplicate = await env.PASARGUARD_DB.prepare(`
    SELECT 'order' AS source_type,id,customer_id FROM sales_orders
      WHERE bot_id=? AND receipt_unique_id=? AND id<>?
    UNION ALL
    SELECT 'wallet' AS source_type,id,customer_id FROM sales_wallet_requests
      WHERE bot_id=? AND receipt_unique_id=? AND id<>?
    LIMIT 1
  `).bind(bot.id, value, currentType === "order" ? currentId : "", bot.id, value, currentType === "wallet" ? currentId : "").first();
  if (!duplicate) return;
  await recordSalesSecurityEvent(env, bot, customer, "duplicate_receipt", "critical", 35, {
    fingerprint: value, duplicateType: duplicate.source_type, duplicateId: duplicate.id
  });
  throw salesSecurityError("این رسید قبلاً در سامانه ثبت شده است.", "DUPLICATE_RECEIPT");
}

async function createSalesOrder(env, bot, customer, planId, options = {}) {
  salesRequireVerifiedPhone(bot, customer);
  const plan = await env.PASARGUARD_DB.prepare("SELECT p.*,COALESCE(l.backend_provider,'pasarguard') AS backend_provider FROM sales_plans p LEFT JOIN sales_locations l ON l.id=p.location_id WHERE p.id=? AND p.bot_id=? AND p.status='active'").bind(planId, bot.id).first();
  if (!plan) throw new Error("این پلن دیگر فعال نیست");
  const expectedPlanType = options.orderType === "renewal" ? "renew" : options.orderType === "volume" ? "volume" : "sale";
  let serviceProvider=normalizeServiceProvider(plan.backend_provider);
  if(expectedPlanType!=="sale"){
    const targetProvider=await env.PASARGUARD_DB.prepare("SELECT service_provider FROM sales_orders WHERE id=? AND bot_id=? AND customer_id=? AND status='delivered'").bind(options.targetOrderId||"",bot.id,customer.id).first();
    if(!targetProvider) throw new Error("سرویس مقصد برای این عملیات پیدا نشد");
    serviceProvider=normalizeServiceProvider(targetProvider.service_provider);
  }else{
    serviceProvider=locationServiceProvider(plan,await getSettings(env),env);
  }
  if (String(plan.plan_type || "sale") !== expectedPlanType) {
    const label = expectedPlanType === "renew" ? "تمدید" : expectedPlanType === "volume" ? "افزایش حجم" : "خرید جدید";
    throw new Error("این پلن برای «" + label + "» قابل استفاده نیست");
  }
  await enforceSalesSecurity(env, bot, customer, options.orderType === "renewal" ? "renewal" : options.orderType === "volume" ? "volume" : "order");
  const orderId = id("ord");
  const ts = nowIso();
  const requestedPaymentMethod = String(options.paymentMethod || resellerPaymentDefaultMethod(bot, "order") || "card").toLowerCase();
  const paymentMethod = ["wallet", "card", "blupal"].includes(requestedPaymentMethod) ? requestedPaymentMethod : "card";
  resellerRequirePaymentMethod(bot, paymentMethod, "order");
  const status = options.status || (paymentMethod === "wallet" ? "pending_review" : paymentMethod === "blupal" ? "payment_pending" : "awaiting_receipt");
  const origin = options.origin === "miniapp" ? "miniapp" : "bot";
  const requestedUsername = expectedPlanType === "sale" && cleanText(options.requestedUsername, 80)
    ? normalizeChosenSubscriptionUsername(options.requestedUsername)
    : null;
  if (expectedPlanType === "sale" && origin === "bot" && !requestedUsername) throw new Error("نام اشتراک انتخاب نشده است");
  const originalPrice = salesCustomerPlanPrice(plan, customer);

  if (["awaiting_receipt", "payment_pending"].includes(status)) {
    const old = await env.PASARGUARD_DB.prepare("SELECT id FROM sales_orders WHERE bot_id=? AND customer_id=? AND status IN ('awaiting_receipt','payment_pending')")
      .bind(bot.id, customer.id).all();
    await env.PASARGUARD_DB.prepare("UPDATE sales_orders SET status='cancelled',updated_at=? WHERE bot_id=? AND customer_id=? AND status IN ('awaiting_receipt','payment_pending')")
      .bind(ts, bot.id, customer.id).run();
    for (const item of old.results || []) try { await salesReleasePromoForOrder(env, item.id); } catch (_) {}
  }

  // An activated code is applied only when the selected plan satisfies its minimum purchase.
  // Otherwise the customer can still buy the plan at the normal/wholesale price and keep the code for a later purchase.
  let promoRef = cleanText(options.promoCode, 80);
  if (!promoRef) {
    const activePromo = await salesActivePromoForCustomer(env, bot.id, customer);
    if (activePromo && originalPrice >= Number(activePromo.min_purchase_toman || 0) && salesPromoDiscountForAmount(activePromo, originalPrice) > 0) {
      promoRef = activePromo.id;
    }
  }
  let promoResult = null;
  if (promoRef) promoResult = await salesReservePromoForOrder(env, bot, customer, promoRef, originalPrice, orderId);
  const discountToman = Number(promoResult?.discount || 0);
  const finalPrice = Math.max(1000, originalPrice - discountToman);

  try {
    await env.PASARGUARD_DB.prepare(`
      INSERT INTO sales_orders(
        id,bot_id,plan_id,customer_id,amount_toman,original_amount_toman,discount_toman,promo_code_id,promo_code,
        status,order_type,target_order_id,payment_method,origin,remote_username,gift_sender_customer_id,gift_message,service_provider,created_at,updated_at
      ) VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)
    `).bind(
      orderId, bot.id, plan.id, customer.id, finalPrice, originalPrice, discountToman,
      promoResult?.promo?.id || null, promoResult?.promo?.code || null,
      status, options.orderType || "new", options.targetOrderId || null, paymentMethod, origin, requestedUsername,
      options.giftSenderCustomerId || null, cleanText(options.giftMessage,500) || null, serviceProvider, ts, ts
    ).run();
  } catch (error) {
    if (promoResult) try { await salesReleasePromoForOrder(env, orderId); } catch (_) {}
    throw error;
  }

  if (status === "awaiting_receipt" && origin !== "miniapp") await salesSessionSet(env, bot.id, customer.telegram_id, "awaiting_receipt", { orderId });
  await salesEvent(env, bot.id, customer.id, "order_created", {
    orderId, planId, paymentMethod, orderType: options.orderType || "new", originalPrice,
    discountToman, finalPrice, promoCode: promoResult?.promo?.code || "", origin, requestedUsername, serviceProvider
  });
  await queueReportEvent(env, bot.id, "orders", "سفارش جدید ثبت شد",
    "مشتری: <b>" + botEscape(customer.first_name || customer.username || customer.telegram_id) + "</b>\n" +
    "پلن: <b>" + botEscape(plan.title) + "</b>\n" +
    "نوع: <b>" + botEscape(options.orderType || "new") + "</b>\n" +
    "مبلغ: <b>" + botMoney(finalPrice) + " تومان</b>\n" +
    "پرداخت: <b>" + botEscape(paymentMethod) + "</b>\n" +
    (requestedUsername ? "نام اشتراک: <code>" + botEscape(requestedUsername) + "</code>\n" : "") +
    "سفارش: <code>" + botEscape(orderId) + "</code>",
    "order-created:" + orderId);
  return {
    orderId, plan, amountToman: finalPrice, originalAmountToman: originalPrice, discountToman,
    promoCode: promoResult?.promo?.code || "", orderType: options.orderType || "new",
    targetOrderId: options.targetOrderId || null, origin, requestedUsername, serviceProvider
  };
}

function requireSalesPaymentCard(bot) {
  const card = normalizeCardNumber(bot.card_number);
  if (card.length < 16 || !cleanText(bot.card_holder, 160)) throw new Error("اطلاعات کارت بانکی نماینده هنوز تکمیل نشده است");
}

function salesMiniAppPaymentPayload(bot, targetType, targetId, amountToman, extra = {}) {
  const bonusPercent = Math.max(0, Math.min(100, Number(extra.bonusPercent || 0)));
  const bonusToman = Math.max(0, Number(extra.bonusToman || 0));
  return {
    target_type: targetType,
    target_id: targetId,
    amount_toman: Number(amountToman || 0),
    original_amount_toman: Number(extra.originalAmountToman || amountToman || 0),
    discount_toman: Number(extra.discountToman || 0),
    promo_code: cleanText(extra.promoCode, 32),
    bonus_percent: bonusPercent,
    bonus_toman: bonusToman,
    final_wallet_credit: Number(amountToman || 0) + bonusToman,
    card_number: formatCardNumber(bot.card_number),
    card_number_raw: normalizeCardNumber(bot.card_number),
    card_holder: cleanText(bot.card_holder, 160),
    bank_name: cleanText(bot.bank_name, 120),
    title: cleanText(extra.title, 200)
  };
}

