      [{ text: loyaltyEnabled ? "🏅 غیرفعال‌کردن باشگاه" : "🏅 فعال‌کردن باشگاه", callback_data: "owner:automation:loyalty" }],
      [{ text: "🎯 الگوی باشگاه: " + profile.label, callback_data: "owner:automation:profile" }],
