function resellerCampaignRecipientQuery(scope) {
  const base = "SELECT c.telegram_id FROM sales_customers c WHERE c.bot_id=? AND c.status='active'";
  const map = {
    buyers: " AND EXISTS(SELECT 1 FROM sales_orders o WHERE o.bot_id=c.bot_id AND o.customer_id=c.id AND o.status='delivered')",
    no_purchase: " AND NOT EXISTS(SELECT 1 FROM sales_orders o WHERE o.bot_id=c.bot_id AND o.customer_id=c.id AND o.status='delivered')",
    wholesale: " AND c.customer_type='wholesale'",
    retail: " AND COALESCE(c.customer_type,'retail')<>'wholesale'",
    verified: " AND c.phone_verified_at IS NOT NULL",
    unverified: " AND c.phone_verified_at IS NULL"
  };
  return base + (map[String(scope || "all")] || "") + " ORDER BY c.created_at LIMIT 2000";
}

async function processSalesCampaign(env, campaign) {
  const bot = await getResellerBotById(env, campaign.bot_id);
  if (!bot) throw new Error("ربات کمپین پیدا نشد");
  const claim = await env.PASARGUARD_DB.prepare("UPDATE sales_campaigns SET status='running',started_at=?,error_message=NULL WHERE id=? AND status='pending'")
    .bind(nowIso(), campaign.id).run();
  if (!Number(claim?.meta?.changes || 0)) return { skipped: true };
  let success = 0, failed = 0;
  try {
    const recipients = await env.PASARGUARD_DB.prepare(resellerCampaignRecipientQuery(campaign.target_scope)).bind(bot.id).all();
    const list = recipients.results || [];
    for (let offset = 0; offset < list.length; offset += 20) {
      const batch = list.slice(offset, offset + 20);
      const results = await Promise.all(batch.map(async recipient => {
        try {
          if (cleanText(campaign.message_text, 4000)) {
            await resellerTelegramApi(env, bot, "sendMessage", { chat_id: recipient.telegram_id, text: cleanText(campaign.message_text, 4000), disable_web_page_preview: true });
          } else {
            const payload = { chat_id: recipient.telegram_id, from_chat_id: campaign.source_chat_id, message_id: campaign.source_message_id };
            await resellerTelegramApi(env, bot, campaign.send_mode === "forward" ? "forwardMessage" : "copyMessage", payload);
          }
          return true;
        } catch (_) { return false; }
      }));
      const ok = results.filter(Boolean).length;
      success += ok;
      failed += results.length - ok;
    }
    await env.PASARGUARD_DB.prepare("UPDATE sales_campaigns SET status='completed',success_count=?,failed_count=?,finished_at=? WHERE id=?")
      .bind(success, failed, nowIso(), campaign.id).run();
    await queueReportEvent(env, bot.id, "announcements", "اطلاع‌رسانی گروهی انجام شد",
      "کمپین: <code>" + botEscape(campaign.id) + "</code>\n" +
      "مخاطبان موفق: <b>" + botMoney(success) + "</b>\n" +
      "ارسال ناموفق: <b>" + botMoney(failed) + "</b>\n" +
      "گروه هدف: <b>" + botEscape(campaign.target_scope || "all") + "</b>",
      "campaign-completed:" + campaign.id);
    return { success, failed };
  } catch (error) {
    await env.PASARGUARD_DB.prepare("UPDATE sales_campaigns SET status='failed',success_count=?,failed_count=?,finished_at=?,error_message=? WHERE id=?")
      .bind(success, failed, nowIso(), cleanText(error.message, 500), campaign.id).run();
    await queueReportEvent(env, bot.id, "errors", "خطا در اطلاع‌رسانی گروهی",
      "کمپین: <code>" + botEscape(campaign.id) + "</code>\n" +
      "ارسال موفق تا لحظه خطا: <b>" + botMoney(success) + "</b>\n" +
      "خطا: <code>" + botEscape(cleanText(error.message, 700)) + "</code>",
      "campaign-failed:" + campaign.id + ":" + cleanText(error.message, 80));
    throw error;
  }
}


function backupDocumentTopicErrorIsRecoverable(error) {
  return /message thread not found|thread.*not found|topic.*closed|topic_closed|forum topic|message_thread_id/i.test(String(error?.message || error || ""));
}

function backupDocumentFileName(bot, snapshotId, snapshotType, createdAt) {
  const botPart = String(bot?.bot_username || bot?.id || "reseller").replace(/[^A-Za-z0-9_-]+/g, "_").slice(0, 42) || "reseller";
  const stamp = String(createdAt || nowIso()).replace(/\D/g, "").slice(0, 14) || String(Date.now());
  const idPart = String(snapshotId || "snapshot").replace(/[^A-Za-z0-9_-]+/g, "_").slice(-18);
  return "pasargad-backup-" + botPart + "-" + (snapshotType === "auto" ? "auto" : "manual") + "-" + stamp + "-" + idPart + ".json";
}

async function sendTelegramBackupDocument(token, chatId, threadId, raw, filename, caption) {
  if (!token) throw new Error("توکن ربات برای ارسال فایل بکاپ تنظیم نشده است");
  const form = new FormData();
  form.set("chat_id", String(chatId));
  if (Number(threadId || 0) > 0) form.set("message_thread_id", String(Number(threadId)));
  form.set("document", new Blob([String(raw || "{}")], { type: "application/json; charset=utf-8" }), filename || "pasargad-backup.json");
  form.set("caption", cleanText(caption, 950));
  form.set("parse_mode", "HTML");
  form.set("disable_content_type_detection", "true");
  const response = await fetch("https://api.telegram.org/bot" + token + "/sendDocument", { method: "POST", body: form });
  const data = await response.json().catch(() => ({}));
  if (!response.ok || data.ok === false) throw new Error(data.description || "ارسال فایل بکاپ به تلگرام ناموفق بود");
  return data;
}

async function ensureBackupDocumentTopic(env, forum, scopeType, bot = null, recreate = false) {
  const scopeKey = String(forum.scope_key || (scopeType === "central" ? "central" : reportScopeKey(bot?.id)));
  const definition = reportTopicDefinition(scopeType, "backups");
  if (recreate) {
    await env.PASARGUARD_DB.prepare("DELETE FROM report_forum_topics WHERE scope_key=? AND topic_key=?")
      .bind(scopeKey, definition.key).run();
  }
  let topic = await env.PASARGUARD_DB.prepare("SELECT thread_id,title FROM report_forum_topics WHERE scope_key=? AND topic_key=?")
    .bind(scopeKey, definition.key).first();
  if (Number(topic?.thread_id || 0) > 0) return { ...topic, topic_key: definition.key };
  const created = scopeType === "central"
    ? await telegramApi(env, "createForumTopic", { chat_id: String(forum.chat_id), name: definition.title, icon_color: definition.color })
    : await resellerTelegramApi(env, bot, "createForumTopic", { chat_id: String(forum.chat_id), name: definition.title, icon_color: definition.color });
  const threadId = Number(created?.result?.message_thread_id || 0);
  if (!threadId) throw new Error("ساخت Topic فایل بکاپ ناموفق بود");
  const ts = nowIso();
  await env.PASARGUARD_DB.prepare(`INSERT INTO report_forum_topics(scope_key,topic_key,thread_id,title,created_at,updated_at)
    VALUES(?,?,?,?,?,?) ON CONFLICT(scope_key,topic_key) DO UPDATE SET thread_id=excluded.thread_id,title=excluded.title,updated_at=excluded.updated_at`)
    .bind(scopeKey, definition.key, threadId, definition.title, ts, ts).run();
  return { thread_id: threadId, title: definition.title, topic_key: definition.key };
}

async function deliverResellerSnapshotDocument(env, bot, raw, snapshotId, snapshotType, createdAt) {
  const result = { central: "skipped", reseller: "skipped", errors: [] };
  const filename = backupDocumentFileName(bot, snapshotId, snapshotType, createdAt);
  const caption = "🗄 <b>فایل بکاپ ربات نماینده</b>\n" +
    "🤖 ربات: <b>" + botEscape(bot?.brand_name || bot?.bot_username || bot?.id || "-") + "</b>\n" +
    "📦 نوع: <b>" + (snapshotType === "auto" ? "خودکار" : "دستی") + "</b>\n" +
    "🆔 شناسه: <code>" + botEscape(snapshotId) + "</code>\n" +
    "🏷 نسخه: <code>" + botEscape(APP_VERSION) + "</code>";
  const targets = [
    { key: "central", scopeKey: "central", scopeType: "central", bot: null },
    { key: "reseller", scopeKey: reportScopeKey(bot.id), scopeType: "reseller", bot }
  ];
  for (const target of targets) {
    const forum = await env.PASARGUARD_DB.prepare("SELECT scope_key,scope_type,bot_id,chat_id,status FROM report_forums WHERE scope_key=? AND status='active'")
      .bind(target.scopeKey).first();
    if (!forum?.chat_id) continue;
    const sendOnce = async (recreate = false) => {
      const topic = await ensureBackupDocumentTopic(env, forum, target.scopeType, target.bot, recreate);
      const token = target.scopeType === "central"
        ? String((await getSettings(env)).bot_token || "")
        : await resellerBotToken(env, target.bot);
      return sendTelegramBackupDocument(token, forum.chat_id, topic.thread_id, raw, filename, caption);
    };
    try {
      try { await sendOnce(false); }
      catch (error) {
        if (!backupDocumentTopicErrorIsRecoverable(error)) throw error;
        await sendOnce(true);
      }
      result[target.key] = "delivered";
      const ts = nowIso();
      await env.PASARGUARD_DB.prepare("UPDATE report_forums SET last_delivery_at=?,last_error=NULL,updated_at=? WHERE scope_key=?")
        .bind(ts, ts, target.scopeKey).run();
    } catch (error) {
      const message = cleanText(String(error?.message || error), 500);
      result[target.key] = "failed";
      result.errors.push((target.key === "central" ? "مرکزی" : "نماینده") + ": " + message);
      await env.PASARGUARD_DB.prepare("UPDATE report_forums SET last_error=?,updated_at=? WHERE scope_key=?")
        .bind(message, nowIso(), target.scopeKey).run().catch(() => null);
    }
  }
  return result;
}

function resellerSnapshotSettings(bot) {
  const out = {};
  for (const key of RESELLER_BACKUP_FIELDS) out[key] = bot?.[key] ?? null;
  return out;
}

async function pruneResellerSnapshots(env, botId, retentionDays = 14) {
  const days = Math.max(1, Math.min(365, Number(retentionDays || 14)));
  const cutoff = new Date(Date.now() - days * 86400000).toISOString();
  const result = await env.PASARGUARD_DB.prepare("DELETE FROM reseller_snapshots WHERE bot_id=? AND created_at<?").bind(botId, cutoff).run();
  return Number(result?.meta?.changes || 0);
}

async function createResellerSnapshot(env, bot, actorTelegramId = "system", snapshotType = "manual") {
  const fresh = await getResellerBotById(env, bot.id);
  if (!fresh) throw new Error("ربات نماینده پیدا نشد");
  try {
    const [locations, categories, plans, texts, promos] = await Promise.all([
      env.PASARGUARD_DB.prepare("SELECT id,title,emoji,description,backend_provider,group_ids_json,status,sort_order,created_at,updated_at FROM sales_locations WHERE bot_id=? ORDER BY sort_order,created_at").bind(fresh.id).all(),
      env.PASARGUARD_DB.prepare("SELECT id,title,emoji,status,sort_order,created_at,updated_at FROM sales_categories WHERE bot_id=? ORDER BY sort_order,created_at").bind(fresh.id).all(),
      env.PASARGUARD_DB.prepare("SELECT id,title,data_limit_bytes,duration_days,price_toman,status,sort_order,category_id,location_id,plan_type,created_at,updated_at FROM sales_plans WHERE bot_id=? AND COALESCE(plan_type,'sale')<>'imported' ORDER BY sort_order,created_at").bind(fresh.id).all(),
      env.PASARGUARD_DB.prepare("SELECT text_key,text_value,updated_at FROM reseller_bot_texts WHERE bot_id=? ORDER BY text_key").bind(fresh.id).all(),
      env.PASARGUARD_DB.prepare("SELECT id,code,kind,value_type,value,min_purchase_toman,max_uses,per_user_limit,use_count,status,expires_at,description,created_at,updated_at FROM sales_promo_codes WHERE bot_id=? ORDER BY created_at").bind(fresh.id).all()
    ]);
    const createdAt = nowIso();
    const payload = {
      schema: 1,
      app_version: APP_VERSION,
      bot_id: fresh.id,
      bot_username: fresh.bot_username,
      created_at: createdAt,
      settings: resellerSnapshotSettings(fresh),
      locations: locations.results || [],
      categories: categories.results || [],
      plans: plans.results || [],
      texts: texts.results || [],
      promos: promos.results || []
    };
    const raw = JSON.stringify(payload);
    const snapshotId = id("snap");
    await env.PASARGUARD_DB.prepare(`
      INSERT INTO reseller_snapshots(id,bot_id,snapshot_type,label,payload_json,size_bytes,created_by_telegram_id,created_at)
      VALUES(?,?,?,?,?,?,?,?)
    `).bind(snapshotId, fresh.id, snapshotType, snapshotType === "auto" ? "پشتیبان خودکار" : "پشتیبان دستی", raw, new TextEncoder().encode(raw).length, String(actorTelegramId || "system"), createdAt).run();
    await env.PASARGUARD_DB.prepare("UPDATE reseller_bots SET last_backup_at=?,last_backup_status='success',last_backup_error=NULL,updated_at=? WHERE id=?")
      .bind(createdAt, createdAt, fresh.id).run();
    await pruneResellerSnapshots(env, fresh.id, fresh.backup_retention_days || 14);
    const fileDelivery = await deliverResellerSnapshotDocument(env, fresh, raw, snapshotId, snapshotType, createdAt);
    await queueReportEvent(env, fresh.id, "backups", snapshotType === "auto" ? "بکاپ خودکار ربات ساخته شد" : "بکاپ دستی ربات ساخته شد",
      "ربات: <b>" + botEscape(fresh.brand_name || fresh.bot_username) + "</b>\n" +
      "نوع: <b>" + (snapshotType === "auto" ? "خودکار" : "دستی") + "</b>\n" +
      "حجم فایل: <b>" + botMoney(new TextEncoder().encode(raw).length) + " بایت</b>\n" +
      "شناسه بکاپ: <code>" + botEscape(snapshotId) + "</code>\n" +
      "فایل گروه مرکزی: <b>" + (fileDelivery.central === "delivered" ? "ارسال شد ✅" : fileDelivery.central === "failed" ? "ناموفق ❌" : "تنظیم نشده") + "</b>\n" +
      "فایل گروه نماینده: <b>" + (fileDelivery.reseller === "delivered" ? "ارسال شد ✅" : fileDelivery.reseller === "failed" ? "ناموفق ❌" : "تنظیم نشده") + "</b>",
      "backup-success:" + snapshotId);
    if (fileDelivery.errors.length) {
      await queueReportEvent(env, fresh.id, "errors", "فایل بکاپ ساخته شد اما ارسال گروه ناقص بود",
        "ربات: <b>" + botEscape(fresh.brand_name || fresh.bot_username) + "</b>\n" +
        "شناسه بکاپ: <code>" + botEscape(snapshotId) + "</code>\n" +
        "جزئیات: <code>" + botEscape(cleanText(fileDelivery.errors.join(" | "), 900)) + "</code>",
        "backup-file-delivery:" + snapshotId);
    }
    return { id: snapshotId, created_at: createdAt, size_bytes: new TextEncoder().encode(raw).length, type: snapshotType, file_delivery: fileDelivery };
  } catch (error) {
    await env.PASARGUARD_DB.prepare("UPDATE reseller_bots SET last_backup_status='failed',last_backup_error=?,updated_at=? WHERE id=?")
      .bind(cleanText(error.message, 500), nowIso(), fresh.id).run();
    await queueReportEvent(env, fresh.id, "errors", "خطا در بکاپ ربات",
      "ربات: <b>" + botEscape(fresh.brand_name || fresh.bot_username) + "</b>\n" +
      "نوع بکاپ: <b>" + (snapshotType === "auto" ? "خودکار" : "دستی") + "</b>\n" +
      "خطا: <code>" + botEscape(cleanText(error.message, 700)) + "</code>",
      "backup-failed:" + fresh.id + ":" + snapshotType + ":" + cleanText(error.message, 80));
    throw error;
  }
}

async function restoreResellerSnapshot(env, bot, account, snapshotId) {
  resellerRequirePermission(account, "owner");
  const row = await env.PASARGUARD_DB.prepare("SELECT * FROM reseller_snapshots WHERE id=? AND bot_id=?").bind(snapshotId, bot.id).first();
  if (!row) throw new Error("نسخه پشتیبان پیدا نشد");
  let payload;
  try { payload = JSON.parse(row.payload_json || "{}"); } catch (_) { throw new Error("محتوای نسخه پشتیبان معتبر نیست"); }
  const settings = payload.settings && typeof payload.settings === "object" ? payload.settings : {};
  const growthKeys = ["auto_renew_enabled","smart_recommendations_enabled","upsell_enabled","favorite_plan_enabled","gift_service_enabled","service_health_enabled","auto_failover_enabled","guarantee_enabled","low_balance_alert_enabled","low_balance_threshold_toman","low_balance_recharge_amount_toman","reseller_tier","reseller_tier_discount_percent"];
  const keys = RESELLER_BACKUP_FIELDS.filter(key => Object.prototype.hasOwnProperty.call(settings, key) && !growthKeys.includes(key));
  if (keys.length) {
    const assignments = keys.map(key => key + "=?").join(",");
    const values = keys.map(key => settings[key]);
    await env.PASARGUARD_DB.prepare("UPDATE reseller_bots SET " + assignments + ",updated_at=? WHERE id=?")
      .bind(...values, nowIso(), bot.id).run();
  }
  const growthRestoreKeys=growthKeys.filter(key=>Object.prototype.hasOwnProperty.call(settings,key));
  if(growthRestoreKeys.length){
    await ensureResellerGrowthSettingsRow(env,bot.id);
    const assignments=growthRestoreKeys.map(key=>key+"=?").join(",");
    const values=growthRestoreKeys.map(key=>settings[key]);
    await env.PASARGUARD_DB.prepare("UPDATE reseller_growth_settings SET "+assignments+",updated_at=? WHERE bot_id=?")
      .bind(...values,nowIso(),bot.id).run();
  }
  for (const x of Array.isArray(payload.locations) ? payload.locations : []) {
    await env.PASARGUARD_DB.prepare(`INSERT INTO sales_locations(id,bot_id,title,emoji,description,backend_provider,group_ids_json,status,sort_order,created_at,updated_at)
      VALUES(?,?,?,?,?,?,?,?,?,?,?) ON CONFLICT(id) DO UPDATE SET title=excluded.title,emoji=excluded.emoji,description=excluded.description,backend_provider=excluded.backend_provider,group_ids_json=excluded.group_ids_json,status=excluded.status,sort_order=excluded.sort_order,updated_at=excluded.updated_at`)
      .bind(x.id,bot.id,x.title,x.emoji||null,x.description||null,normalizeServiceProvider(x.backend_provider),x.group_ids_json||"[]",x.status||"active",Number(x.sort_order||0),x.created_at||nowIso(),nowIso()).run();
  }
  for (const x of Array.isArray(payload.categories) ? payload.categories : []) {
    await env.PASARGUARD_DB.prepare(`INSERT INTO sales_categories(id,bot_id,title,emoji,status,sort_order,created_at,updated_at)
      VALUES(?,?,?,?,?,?,?,?) ON CONFLICT(id) DO UPDATE SET title=excluded.title,emoji=excluded.emoji,status=excluded.status,sort_order=excluded.sort_order,updated_at=excluded.updated_at`)
      .bind(x.id,bot.id,x.title,x.emoji||null,x.status||"active",Number(x.sort_order||0),x.created_at||nowIso(),nowIso()).run();
  }
  for (const x of Array.isArray(payload.plans) ? payload.plans : []) {
    await env.PASARGUARD_DB.prepare(`INSERT INTO sales_plans(id,bot_id,title,data_limit_bytes,duration_days,price_toman,status,sort_order,category_id,location_id,plan_type,created_at,updated_at)
      VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?) ON CONFLICT(id) DO UPDATE SET title=excluded.title,data_limit_bytes=excluded.data_limit_bytes,duration_days=excluded.duration_days,price_toman=excluded.price_toman,status=excluded.status,sort_order=excluded.sort_order,category_id=excluded.category_id,location_id=excluded.location_id,plan_type=excluded.plan_type,updated_at=excluded.updated_at`)
      .bind(x.id,bot.id,x.title,Number(x.data_limit_bytes||0),Number(x.duration_days||0),Number(x.price_toman||0),x.status||"active",Number(x.sort_order||0),x.category_id||null,x.location_id||null,x.plan_type||"sale",x.created_at||nowIso(),nowIso()).run();
  }
  for (const x of Array.isArray(payload.texts) ? payload.texts : []) {
    await env.PASARGUARD_DB.prepare(`INSERT INTO reseller_bot_texts(bot_id,text_key,text_value,updated_at) VALUES(?,?,?,?)
      ON CONFLICT(bot_id,text_key) DO UPDATE SET text_value=excluded.text_value,updated_at=excluded.updated_at`)
      .bind(bot.id,x.text_key,x.text_value||"",nowIso()).run();
  }
  for (const x of Array.isArray(payload.promos) ? payload.promos : []) {
    await env.PASARGUARD_DB.prepare(`INSERT INTO sales_promo_codes(id,bot_id,code,kind,value_type,value,min_purchase_toman,max_uses,per_user_limit,use_count,status,expires_at,description,created_at,updated_at)
      VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?,?,?) ON CONFLICT(id) DO UPDATE SET code=excluded.code,kind=excluded.kind,value_type=excluded.value_type,value=excluded.value,min_purchase_toman=excluded.min_purchase_toman,max_uses=excluded.max_uses,per_user_limit=excluded.per_user_limit,status=excluded.status,expires_at=excluded.expires_at,description=excluded.description,updated_at=excluded.updated_at`)
      .bind(x.id,bot.id,x.code,x.kind||"discount",x.value_type||"percent",Number(x.value||0),Number(x.min_purchase_toman||0),Number(x.max_uses||0),Number(x.per_user_limit||1),Number(x.use_count||0),x.status||"active",x.expires_at||null,x.description||null,x.created_at||nowIso(),nowIso()).run();
  }
  await resellerAudit(env, bot, account, "snapshot_restored", { snapshot_id: snapshotId, created_at: row.created_at });
  return { snapshot_id: snapshotId, created_at: row.created_at };
}

async function runResellerHealthCheck(env, bot) {
  const details=[];
  let score=100;
  const add=(key,label,status,message,penalty=0)=>{ details.push({key,label,status,message}); if(status!=="ok") score-=penalty; };
  try { await env.PASARGUARD_DB.prepare("SELECT 1 AS ok").first(); add("database","دیتابیس","ok","اتصال D1 برقرار است"); }
  catch(error){ add("database","دیتابیس","error",cleanText(error.message,180),35); }
  try {
    const me=await resellerTelegramApi(env,bot,"getMe",{});
    add("telegram","ربات تلگرام","ok","@"+String(me?.result?.username||bot.bot_username||"bot"));
  } catch(error){ add("telegram","ربات تلگرام","error",cleanText(error.message,180),25); }
  try {
    const info=await resellerTelegramApi(env,bot,"getWebhookInfo",{});
    const url=String(info?.result?.url||"");
    const pending=Number(info?.result?.pending_update_count||0);
    if(!url || !url.includes("/sales-bot/"+bot.id+"/webhook")) add("webhook","Webhook","warning","آدرس Webhook با ربات همگام نیست",12);
    else if(pending>100) add("webhook","Webhook","warning","صف بروزرسانی تلگرام: "+pending,8);
    else add("webhook","Webhook","ok","فعال · صف "+pending);
  } catch(error){ add("webhook","Webhook","error",cleanText(error.message,180),18); }
  try {
    const agency=await env.PASARGUARD_DB.prepare("SELECT * FROM agencies WHERE id=?").bind(bot.agency_id).first();
    if(!agency) throw new Error("پنل متصل پیدا نشد");
    await getAgencyPasarguardToken(env,agency,true);
    add("panel","پنل PasarGuard","ok","ورود پنل موفق بود");
  } catch(error){ add("panel","پنل PasarGuard","error",cleanText(error.message,180),25); }
  if(Number(bot.blupal_enabled||0)===1){
    if(String(bot.blupal_api_key_enc||"").trim()) add("blupal","بلوپال","ok","API رمزگذاری‌شده و درگاه فعال است");
    else add("blupal","بلوپال","error","درگاه فعال است اما API Key ثبت نشده",18);
  } else add("blupal","بلوپال","idle","غیرفعال",0);
  if(Number(bot.auto_backup_enabled??1)===1){
    const age=bot.last_backup_at ? Date.now()-new Date(bot.last_backup_at).getTime() : Number.POSITIVE_INFINITY;
    if(age>48*3600000) add("backup","پشتیبان‌گیری","warning","بیش از ۴۸ ساعت پشتیبان موفق ثبت نشده",10);
    else add("backup","پشتیبان‌گیری","ok","آخرین پشتیبان: "+botDate(bot.last_backup_at));
  } else add("backup","پشتیبان‌گیری","idle","پشتیبان خودکار غیرفعال است",0);
  const pending=await env.PASARGUARD_DB.prepare(`SELECT
    (SELECT COUNT(*) FROM sales_orders WHERE bot_id=? AND status='pending_review') AS orders_count,
    (SELECT COUNT(*) FROM sales_payment_invoices WHERE bot_id=? AND status IN ('PENDING','PAID') AND processed_at IS NULL) AS payments_count,
    (SELECT COUNT(*) FROM sales_tickets WHERE bot_id=? AND status='waiting_owner') AS tickets_count`).bind(bot.id,bot.id,bot.id).first();
  const queue=Number(pending?.orders_count||0)+Number(pending?.payments_count||0)+Number(pending?.tickets_count||0);
  if(queue>30) add("queue","صف عملیاتی","warning","تعداد موارد نیازمند رسیدگی: "+queue,8);
  else add("queue","صف عملیاتی","ok","موارد نیازمند رسیدگی: "+queue);
  score=Math.max(0,Math.min(100,Math.round(score)));
  const overall=score>=85?"healthy":score>=60?"warning":"critical";
  const checkId=id("health");
  await env.PASARGUARD_DB.prepare("INSERT INTO reseller_health_checks(id,bot_id,overall_status,score,details_json,created_at) VALUES(?,?,?,?,?,?)")
    .bind(checkId,bot.id,overall,score,JSON.stringify(details),nowIso()).run();
  return {id:checkId,overall_status:overall,score,details,created_at:nowIso()};
}

async function resellerOwnerBackupsView(env, bot, account) {
  resellerRequirePermission(account,"backups");
  const fresh=await getResellerBotById(env,bot.id);
  const rows=await env.PASARGUARD_DB.prepare("SELECT id,snapshot_type,size_bytes,created_at,created_by_telegram_id FROM reseller_snapshots WHERE bot_id=? ORDER BY created_at DESC LIMIT 6").bind(bot.id).all();
  const list=rows.results||[];
  const lines=list.length?list.map((x,i)=>(i+1)+". "+(x.snapshot_type==="auto"?"⏱ خودکار":"👤 دستی")+" · <b>"+botDate(x.created_at)+"</b> · "+botMoney(Math.ceil(Number(x.size_bytes||0)/1024))+" KB").join("\n"):"هنوز نسخه پشتیبانی ساخته نشده است.";
  return {text:"🗄 <b>مرکز پشتیبان‌گیری</b>\n━━━━━━━━━━━━━━\n"+
    "پشتیبان خودکار: <b>"+(Number(fresh.auto_backup_enabled??1)===1?"🟢 فعال":"🔴 غیرفعال")+"</b>\n"+
    "ساعت اجرا UTC: <b>"+botMoney(fresh.backup_hour_utc||2)+":00</b>\n"+
    "مدت نگهداری: <b>"+botMoney(fresh.backup_retention_days||14)+" روز</b>\n"+
    "آخرین وضعیت: <b>"+botEscape(fresh.last_backup_status||"ثبت نشده")+"</b>\n"+
    (fresh.last_backup_error?"⚠️ خطا: <code>"+botEscape(fresh.last_backup_error)+"</code>\n":"")+
    "\n<b>آخرین نسخه‌ها</b>\n"+lines+"\n\n🔒 کاربران، سفارش‌ها، کیف پول‌ها، رسیدها و APIهای محرمانه در بازیابی حذف یا بازنویسی نمی‌شوند.",
    reply_markup:{inline_keyboard:[
      [{text:"➕ ساخت پشتیبان اکنون",callback_data:"owner:backup:create"}],
      [{text:"♻️ بازیابی آخرین نسخه",callback_data:"owner:backup:restore_latest"}],
      [{text:Number(fresh.auto_backup_enabled??1)===1?"⏸ توقف پشتیبان خودکار":"▶️ فعال‌کردن پشتیبان خودکار",callback_data:"owner:backup:toggle"}],
      [{text:"🕑 تغییر ساعت اجرا",callback_data:"owner:backup:hour"},{text:"🗓 تغییر نگهداری",callback_data:"owner:backup:retention"}],
      [{text:"↩️ مدیریت ربات",callback_data:"owner:home"}]
    ]}};
}

async function resellerOwnerHealthView(env, bot, account) {
  resellerRequirePermission(account,"health");
  const fresh=await getResellerBotById(env,bot.id);
  let check;
  try{check=await runResellerHealthCheck(env,fresh);}catch(error){check={overall_status:"critical",score:0,details:[{label:"اجرای پایش",status:"error",message:error.message}],created_at:nowIso()};}
  const icon={ok:"✅",warning:"⚠️",error:"❌",idle:"▫️"};
  const overall=check.overall_status==="healthy"?"🟢 پایدار":check.overall_status==="warning"?"🟠 نیازمند توجه":"🔴 بحرانی";
  const lines=(check.details||[]).map(x=>(icon[x.status]||"•")+" <b>"+botEscape(x.label)+"</b> — "+botEscape(x.message||"—")).join("\n");
  return {text:"🩺 <b>مرکز سلامت سیستم</b>\n━━━━━━━━━━━━━━\nوضعیت کلی: <b>"+overall+"</b>\nامتیاز سلامت: <b>"+botMoney(check.score)+" از ۱۰۰</b>\nزمان بررسی: <b>"+botDate(check.created_at)+"</b>\n\n"+lines,
    reply_markup:{inline_keyboard:[[{text:"🔄 اجرای دوباره پایش",callback_data:"owner:health"}],[{text:"🗄 پشتیبان‌گیری",callback_data:"owner:backups"}],[{text:"↩️ مدیریت ربات",callback_data:"owner:home"}]]}};
}

async function resellerPeriodStats(env, botId, startIso) {
  return env.PASARGUARD_DB.prepare(`SELECT
    (SELECT COUNT(*) FROM sales_orders WHERE bot_id=? AND created_at>=?) AS orders_count,
    (SELECT COUNT(*) FROM sales_orders WHERE bot_id=? AND status='delivered' AND created_at>=?) AS delivered_count,
    (SELECT COALESCE(SUM(amount_toman),0) FROM sales_orders WHERE bot_id=? AND status='delivered' AND created_at>=?) AS revenue,
    (SELECT COALESCE(SUM(discount_toman),0) FROM sales_orders WHERE bot_id=? AND status='delivered' AND created_at>=?) AS discounts,
    (SELECT COALESCE(SUM(cashback_toman),0) FROM sales_orders WHERE bot_id=? AND status='delivered' AND created_at>=?) AS cashback,
    (SELECT COALESCE(SUM(CASE WHEN amount<0 THEN -amount ELSE 0 END),0) FROM wallet_ledger
       WHERE user_id=(SELECT user_id FROM reseller_bots WHERE id=?) AND type='usage_charge' AND created_at>=?) AS usage_cost,
    (SELECT COUNT(*) FROM sales_customers WHERE bot_id=? AND created_at>=?) AS new_customers,
    (SELECT COUNT(*) FROM sales_tickets WHERE bot_id=? AND created_at>=?) AS tickets_count`)
    .bind(botId,startIso,botId,startIso,botId,startIso,botId,startIso,botId,startIso,botId,startIso,botId,startIso,botId,startIso).first();
}

async function resellerOwnerExecutiveReportView(env, bot, account) {
  resellerRequirePermission(account,"reports");
  const now=new Date();
  const today=new Date(Date.UTC(now.getUTCFullYear(),now.getUTCMonth(),now.getUTCDate())).toISOString();
  const week=new Date(Date.now()-7*86400000).toISOString();
  const month=new Date(Date.UTC(now.getUTCFullYear(),now.getUTCMonth(),1)).toISOString();
  const [d,w,m,top]=await Promise.all([
    resellerPeriodStats(env,bot.id,today),resellerPeriodStats(env,bot.id,week),resellerPeriodStats(env,bot.id,month),
    env.PASARGUARD_DB.prepare(`SELECT p.title,COUNT(*) AS c,COALESCE(SUM(o.amount_toman),0) AS revenue FROM sales_orders o JOIN sales_plans p ON p.id=o.plan_id
      WHERE o.bot_id=? AND o.status='delivered' AND o.created_at>=? GROUP BY p.id,p.title ORDER BY c DESC,revenue DESC LIMIT 3`).bind(bot.id,month).all()
  ]);
  const period=(label,x)=>{const orders=Number(x?.orders_count||0),delivered=Number(x?.delivered_count||0),rate=orders?Math.round(delivered*100/orders):0,revenue=Number(x?.revenue||0),usageCost=Number(x?.usage_cost||0),cashback=Number(x?.cashback||0),profit=revenue-usageCost-cashback;return "<b>"+label+"</b>\n🧾 سفارش: "+botMoney(orders)+" · ✅ تحویل: "+botMoney(delivered)+" · تبدیل: "+botMoney(rate)+"٪\n💰 فروش: "+botMoney(revenue)+" تومان · هزینه مصرف: "+botMoney(usageCost)+"\n🎁 کش‌بک: "+botMoney(cashback)+" · <b>سود خالص: "+botMoney(profit)+" تومان</b>\n👤 کاربر جدید: "+botMoney(x?.new_customers||0)+" · 🎫 تیکت: "+botMoney(x?.tickets_count||0);};
  const topLines=(top.results||[]).length?(top.results||[]).map((x,i)=>(i+1)+". <b>"+botEscape(x.title)+"</b> · "+botMoney(x.c)+" فروش · "+botMoney(x.revenue)+" تومان").join("\n"):"فروش موفقی در ماه جاری ثبت نشده است.";
  return {text:"📈 <b>گزارش اجرایی نماینده</b>\n━━━━━━━━━━━━━━\n"+period("امروز",d)+"\n\n"+period("هفت روز اخیر",w)+"\n\n"+period("ماه جاری",m)+"\n\n🏆 <b>پلن‌های پرفروش ماه</b>\n"+topLines,
    reply_markup:{inline_keyboard:[[{text:"🔄 بروزرسانی گزارش",callback_data:"owner:executive"}],[{text:"↩️ مدیریت ربات",callback_data:"owner:home"}]]}};
}

