    await env.PASARGUARD_DB.prepare("UPDATE reseller_bots SET trial_data_limit_bytes=?,trial_duration_hours=?,trial_duration_days=?,updated_at=? WHERE id=?").bind(Number(session.data.mb) * 1024 * 1024, hours, Math.max(1, Math.ceil(hours / 24)), nowIso(), bot.id).run();
