async function resellerBlupalWebhook(request, env, ctx, botId) {
  await ensureDb(env);
  const bot = await getResellerBotById(env, botId);
  if (!bot) return fail("Not found", 404, "NOT_FOUND");
  const url = new URL(request.url);
  const supplied = url.searchParams.get("token") || request.headers.get("x-webhook-token") || "";
  if (!bot.blupal_webhook_token || !constantTimeTextEqual(supplied, bot.blupal_webhook_token)) return fail("Forbidden", 403, "FORBIDDEN");
  const payload = await parseBody(request);
  if (!payload || payload.success !== true || payload.event !== "payment.completed" || normalizePaymentStatus(payload.status) !== "PAID" || !payload.invoice_id) {
    return fail("Invalid webhook payload", 400, "INVALID_WEBHOOK");
  }
  ctx.waitUntil((async () => {
    const payment = await env.PASARGUARD_DB.prepare("SELECT * FROM sales_payment_invoices WHERE bot_id=? AND provider='blupal' AND provider_invoice_id=?")
      .bind(bot.id, cleanText(payload.invoice_id, 100)).first();
    if (!payment) return;
    try { await reconcileSalesBlupalInvoice(env, payment); }
    catch (error) { await env.PASARGUARD_DB.prepare("UPDATE sales_payment_invoices SET error_message=?,updated_at=? WHERE id=?").bind(cleanText(error.message,800),nowIso(),payment.id).run(); }
  })());
  return json({ received: true });
}

