window.shareLink=function(x){var value=decodeURIComponent(x),url="https://t.me/share/url?url="+encodeURIComponent(value);if(tg&&tg.openTelegramLink)tg.openTelegramLink(url);else location.href=url};
window.openLink=function(x){var url=decodeURIComponent(x);if(tg&&tg.openTelegramLink&&/^https:\/\/t\.me\//i.test(url))tg.openTelegramLink(url);else if(tg&&tg.openLink)tg.openLink(url);else location.href=url};
