          env.PASARGUARD_DB.prepare("UPDATE users SET wallet_balance=wallet_balance+?,updated_at=? WHERE id=?").bind(fee,ts,bot.user_id),
          env.PASARGUARD_DB.prepare("UPDATE reseller_bots SET license_expires_at=?,license_last_renewed_at=?,license_renewal_count=license_renewal_count+1,license_notice_key=NULL,status=CASE WHEN status='expired' THEN 'active' ELSE status END,updated_at=? WHERE id=? AND parent_bot_id=?").bind(expires,ts,ts,child.id,bot.id)
