        const salt=randomHex(16);const hash=await hashResellerControlPassword(password,salt);
        await env.PASARGUARD_DB.prepare("UPDATE reseller_bots SET control_username=?,control_password_hash=?,control_password_salt=?,updated_at=? WHERE id=? AND parent_bot_id=?").bind(username,hash,salt,nowIso(),child.id,bot.id).run();
        return json({success:true,message:"نام کاربری و رمز مدیریت نماینده تغییر کرد",credentials:{username,password}});
