  function setAmountChips(min){var values=[min,min*2,min*5,min*10],ids=['amountChip1','amountChip2','amountChip3','amountChip4'];ids.forEach(function(k,i){var b=el(k);b.textContent=money(values[i]);b.dataset.amount=values[i];b.onclick=function(){el('paymentAmount').value=b.dataset.amount;document.querySelectorAll('.amount-chip').forEach(function(x){x.classList.remove('active')});b.classList.add('active')}})}

  function setLiveUsageStatus(mode,text,sub){
    var box=el('liveUsageStatus'),note=el('liveUsageUpdated');
    if(box){box.className='live-state '+(mode||'');var label=box.querySelector('span:last-child');if(label)label.textContent=text||'زنده'}
    if(note)note.textContent=sub||'مصرف به‌صورت زنده بروزرسانی می‌شود';
  }
  function renderLiveUsage(){
    if(!state)return;
    var a=state.agencies||[],u=state.user||{},active=a.filter(function(x){return x.status==='active'}).length,suspended=a.length-active;
    el('balance').textContent=money(u.wallet_balance);
    el('activeCount').textContent=money(active);
    el('totalUsage').textContent=gb(a.reduce(function(t,x){return t+Number(x.last_usage_bytes||0)},0));
    el('totalCharged').textContent=money(a.reduce(function(t,x){return t+Number(x.total_charged||0)},0))+' تومان';
    if(el('agencyTotalCount'))el('agencyTotalCount').textContent=money(a.length);
    if(el('agencyActiveCount'))el('agencyActiveCount').textContent=money(active);
    if(el('agencySuspendedCount'))el('agencySuspendedCount').textContent=money(suspended);
    renderLedger('ledgerList',(state.ledger||[]).slice(0,5));
    renderLedger('fullLedger',state.ledger||[]);
    renderAgencies();
    renderAgencyPreview(a);
  }
  async function refreshLiveUsage(){
    if(!state||liveUsageBusy||document.hidden)return;
    if(!(state.agencies||[]).length){setLiveUsageStatus('idle','بدون پنل','پس از ساخت نمایندگی، مصرف زنده نمایش داده می‌شود');return}
    liveUsageBusy=true;
    setLiveUsageStatus('syncing','در حال بروزرسانی','در حال دریافت مصرف تازه از PasarGuard…');
    try{
      var d=await api('/api/usage/live');
      state.user.wallet_balance=Number(d.wallet_balance||0);
      state.agencies=d.agencies||[];
      state.ledger=d.ledger||state.ledger||[];
      renderLiveUsage();
      var stamp=new Date(d.server_time||Date.now()).toLocaleTimeString('fa-IR',{hour:'2-digit',minute:'2-digit',second:'2-digit'});
      if(d.errors&&d.errors.length){
        var first=d.errors[0]||{},detail=String(first.message||first.error||'خطای نامشخص'),title=String(first.agencyTitle||'یک پنل');
        setLiveUsageStatus('error',money(d.errors.length)+' پنل ناموفق','آخرین بروزرسانی '+stamp+' · '+title+': '+detail.slice(0,92));
        var liveBox=el('liveUsageStatus');if(liveBox){liveBox.title=(d.errors||[]).map(function(x){return (x.agencyTitle||x.agencyId||'پنل')+': '+(x.message||x.error||'خطا')}).join('\n');liveBox.onclick=function(){toast(liveBox.title||detail)}}
      } else {
        var liveBox=el('liveUsageStatus');if(liveBox){liveBox.title='';liveBox.onclick=null}
        setLiveUsageStatus('','زنده','آخرین بروزرسانی '+stamp+(Number(d.charged||0)>0?' · کسر '+money(d.charged)+' تومان':''));
      }
    }catch(e){
      setLiveUsageStatus('error','اتصال مجدد','نمایش اطلاعات ذخیره‌شده · '+String(e.message||'خطای اتصال').slice(0,105));
    }finally{liveUsageBusy=false}
  }
  function startLiveUsage(){
    clearInterval(liveUsageTimer);
    setTimeout(refreshLiveUsage,700);
    liveUsageTimer=setInterval(refreshLiveUsage,LIVE_USAGE_INTERVAL);
  }
  function render(){var u=state.user,s=state.settings,a=state.agencies||[],p=state.payments||[];el('brand').textContent=s.brand_name;var name=u.first_name||u.username||'کاربر';el('hello').textContent='سلام '+name;el('avatar').textContent=String(name).trim().slice(0,1).toUpperCase()||'P';el('balance').textContent=money(u.wallet_balance);el('pricePerGb').textContent=money(s.price_per_gb)+' تومان';var active=a.filter(function(x){return x.status==='active'}).length,suspended=a.filter(function(x){return x.status!=='active'}).length;el('activeCount').textContent=money(active);el('totalUsage').textContent=gb(a.reduce(function(t,x){return t+Number(x.last_usage_bytes||0)},0));el('totalCharged').textContent=money(a.reduce(function(t,x){return t+Number(x.total_charged||0)},0))+' تومان';el('pendingCount').textContent=money(p.filter(function(x){return String(x.status).toUpperCase()==='PENDING'}).length);var insight=state.dashboard_insight||{};if(el('healthScore')){el('healthScore').textContent=money(insight.score==null?88:insight.score);el('healthScore').className='health-score '+(insight.tone||'good')}if(el('accountInsight')){el('accountInsight').className='insight-strip '+(insight.tone||'good');el('accountInsight').innerHTML='<b>'+esc(insight.title||'حساب آماده فعالیت است')+'</b><span>'+esc(insight.message||'وضعیت حساب شما پایدار است.')+'</span>'}if(el('agencyTotalCount'))el('agencyTotalCount').textContent=money(a.length);if(el('agencyActiveCount'))el('agencyActiveCount').textContent=money(active);if(el('agencySuspendedCount'))el('agencySuspendedCount').textContent=money(suspended);el('paymentAmount').min=s.min_recharge;el('paymentAmount').placeholder='حداقل '+money(s.min_recharge);setAmountChips(Number(s.min_recharge||10000));el('setupFeeNote').textContent=s.agency_sales_enabled===false?'فروش پنل نمایندگی موقتاً توسط مدیریت مرکزی بسته است.':'حداقل موجودی لازم: '+money(s.setup_fee)+' تومان — پس از ساخت کسر نمی‌شود';if(el('agencyCreateCard'))el('agencyCreateCard').style.display=(s.agency_sales_enabled===false)?'none':'';if(el('focusAgencyForm'))el('focusAgencyForm').style.display=(s.agency_sales_enabled===false)?'none':'';renderLedger('ledgerList',(state.ledger||[]).slice(0,5));renderLedger('fullLedger',state.ledger||[]);renderPayments();renderAgencies();renderAgencyPreview(a);renderCentralTrial();fillAdmin()}
  function showCentralWebLogin(message){el('app').style.display='none';var msg=message?'<div class="web-login-note" style="color:var(--danger)">'+esc(message)+'</div>':'';el('loading').style.display='grid';var title=CONTROL_MODE?'ورود به مدیریت مرکزی':'ورود به BluePanel';var subtitle=CONTROL_MODE?'با نام کاربری و رمز مدیر پنل PasarGuard وارد شوید.':'با نام کاربری و رمز همان پنل PasarGuard وارد شوید.';var endpoint=CONTROL_MODE?'/api/auth/control/login':'/api/auth/web/login';el('loading').innerHTML='<div class="web-login-shell"><div class="web-login-logo">BP</div><h2>'+title+'</h2><div class="card-sub">'+subtitle+'</div>'+msg+'<form id="centralWebLoginForm" style="margin-top:18px"><div class="field"><label>نام کاربری پنل</label><input id="webPanelUsername" class="input ltr" autocomplete="username" required></div><div class="field"><label>رمز عبور پنل</label><input id="webPanelPassword" class="input ltr" type="password" autocomplete="current-password" required></div><button id="centralWebLoginBtn" class="btn" type="submit" style="width:100%">ورود امن</button></form><div class="web-login-note">'+(CONTROL_MODE?'آدرس مدیریت ثابت است و ورود یک‌بارمصرف حذف شده است.':'این ورود مستقیماً با PasarGuard بررسی می‌شود. پنل‌های دستی نیز پس از ورود معتبر به حساب متصل می‌شوند.')+'</div></div>';el('centralWebLoginForm').onsubmit=async function(e){e.preventDefault();var btn=el('centralWebLoginBtn');btn.disabled=true;try{var r=await fetch(endpoint+'?_bpv=__APP_VERSION__&_t='+Date.now(),{method:'POST',credentials:'same-origin',cache:'no-store',redirect:'manual',headers:{'content-type':'application/json','accept':'application/json','x-bluepanel-client-version':'__APP_VERSION__'},body:JSON.stringify({username:el('webPanelUsername').value,password:el('webPanelPassword').value})}),raw=await r.text(),d;try{d=JSON.parse(raw)}catch(_){var clean=String(raw||'').replace(/<[^>]*>/g,' ').replace(/\s+/g,' ').trim().slice(0,180);throw new Error('پاسخ نامعتبر سرور (HTTP '+r.status+')'+(clean?': '+clean:''))}if(!r.ok||d.success===false)throw Object.assign(new Error(d.error||'ورود ناموفق بود'),{code:d.code});el('webPanelPassword').value='';el('loading').innerHTML='<div><div class="spinner"></div><div class="card-sub">در حال ورود…</div></div>';await load()}catch(err){toast(err.message)}finally{btn.disabled=false}}}

  async function centralWebLogout(){try{await fetch('/api/auth/web/logout',{method:'POST',credentials:'same-origin'})}catch(_){}location.reload()}
  async function load(){try{state=await api('/api/bootstrap');if(CONTROL_MODE&&!(state.user&&state.user.role==='admin'&&state.admin)){var ce=new Error('دسترسی مدیریت مرکزی لازم است');ce.code='ADMIN_REQUIRED';throw ce}render();if(CONTROL_MODE)go('admin');el('loading').style.display='none';el('app').style.display='block';if(!isTelegram&&!el('centralWebLogout')){var actions=document.querySelector('.top-actions');if(actions){var out=document.createElement('button');out.id='centralWebLogout';out.className='btn secondary small';out.textContent='خروج';out.onclick=centralWebLogout;actions.appendChild(out)}}startLiveUsage()}catch(e){if(e.code==='JOIN_REQUIRED'){var links=(e.channels||[]).filter(function(x){return x.url}).map(function(x){return '<a class="btn secondary" style="display:block;text-decoration:none;margin-top:8px" href="'+esc(x.url)+'">📢 '+esc(x.title)+'</a>'}).join('');el('loading').innerHTML='<div class="card" style="max-width:520px;width:100%"><div class="empty"><div class="empty-icon">🔐</div><b>عضویت اجباری</b><span>ابتدا در کانال‌های تعیین‌شده عضو شوید.</span>'+links+'<button class="btn" style="margin-top:10px" onclick="location.reload()">✅ بررسی مجدد</button></div></div>'}else if(e.code==='WEB_LOGIN_REQUIRED'&&!isTelegram){showCentralWebLogin()}else{el('loading').innerHTML='<div class="card" style="max-width:520px;width:100%"><div class="empty"><div class="empty-icon">!</div><b>خطای ورود</b><span>'+esc(e.message)+'</span><div class="card-sub" style="margin-top:10px">اتصال خود را بررسی و دوباره تلاش کنید.</div></div></div>'}}}
