const SETUP_HTML = String.raw`<!doctype html><html lang="fa" dir="rtl"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>نصب مینی‌اپ پاسارگارد</title><style>
*{box-sizing:border-box;-webkit-tap-highlight-color:transparent}:root{color-scheme:light;--text:#182238;--muted:#6e7b91;--line:rgba(60,79,112,.12);--primary:#536ff2;--ok:#159e6d;--err:#dc5269}body{margin:0;min-height:100vh;background:radial-gradient(circle at 90% -5%,rgba(117,145,255,.24),transparent 31%),radial-gradient(circle at -8% 28%,rgba(255,165,126,.20),transparent 28%),linear-gradient(180deg,#fbfcff,#f3f6fb);color:var(--text);font-family:Tahoma,Arial,sans-serif}.wrap{max-width:820px;margin:auto;padding:28px 18px 48px}.wrap>h1{font-size:27px;margin:0 0 8px}.card{background:rgba(255,255,255,.94);border:1px solid var(--line);border-radius:24px;padding:20px;margin:14px 0;box-shadow:0 18px 50px rgba(53,70,102,.09)}.card h3{margin-top:0}.grid{display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:12px}.field{margin:12px 0}label{display:block;color:var(--muted);font-size:11px;margin-bottom:7px}input{width:100%;padding:13px 14px;border-radius:14px;border:1px solid var(--line);background:#f7f9fc;color:var(--text);font:inherit;outline:none}input:focus{background:#fff;border-color:rgba(83,111,242,.58);box-shadow:0 0 0 4px rgba(83,111,242,.09)}.ltr{direction:ltr;text-align:left}button{width:100%;border:0;border-radius:15px;padding:14px;background:linear-gradient(135deg,#536ff2,#7960eb);color:white;font-weight:bold;font:inherit;cursor:pointer;box-shadow:0 13px 28px rgba(83,111,242,.20)}.muted{color:var(--muted);font-size:11px;line-height:1.9}.ok{color:var(--ok)}.err{color:var(--err)}.webhook{word-break:break-all;background:#f1f5ff;border:1px dashed rgba(83,111,242,.44);border-radius:14px;padding:12px;margin-top:12px}@media(max-width:620px){.grid{grid-template-columns:1fr}.wrap{padding:20px 13px 36px}.wrap>h1{font-size:23px}}
</style></head><body><div class="wrap"><h1>نصب مینی‌اپ نمایندگی</h1><div class="muted">فقط Binding دیتابیس <b>PASARGUARD_DB</b> باید از داشبورد Worker متصل باشد. تمام تنظیمات دیگر در همین صفحه و پنل مدیریت ذخیره می‌شوند.</div><div id="status" class="card">در حال بررسی…</div><form id="form" style="display:none"><div class="card"><h3>مدیر و ربات</h3><div class="field"><label>رمز مدیریت نصب؛ حداقل ۸ کاراکتر</label><input id="setupPassword" type="password" required></div><div class="field"><label>Telegram ID مدیران؛ با کاما جدا کنید</label><input id="adminIds" class="ltr" required></div><div class="field"><label>توکن ربات BotFather</label><input id="botToken" class="ltr" type="password" required></div><div class="field"><label>آدرس نهایی مینی‌اپ؛ خالی یعنی همین دامنه</label><input id="appUrl" class="ltr"></div></div><div class="card"><h3>تنظیمات مالی و بلوپال</h3><div class="field"><label>نام برند</label><input id="brand" value="پنل نمایندگی پاسارگارد"></div><div class="grid"><div class="field"><label>قیمت هر گیگ تومان</label><input id="price" type="number" value="2000"></div><div class="field"><label>حداقل موجودی لازم برای ساخت پنل؛ تومان</label><input id="fee" type="number" value="0"><div class="muted">این مبلغ هزینه قابل برداشت نیست و پس از ساخت در کیف پول کاربر باقی می‌ماند.</div></div></div><div class="field"><label>حداقل شارژ تومان؛ حداقل فنی بلوپال ۱۰,۰۰۰ تومان است</label><input id="minRecharge" type="number" value="100000" min="10000"></div><div class="field"><label>BluePal Base URL</label><input id="blupalBase" class="ltr" value="https://blupal.net/api"></div><div class="field"><label>BluePal API Key</label><input id="blupalApiKey" class="ltr" type="password" required></div><div class="field"><label>شماره کارت اختیاری؛ خالی یعنی بلوپال یک کارت فعال انتخاب کند</label><input id="blupalCard" class="ltr"></div></div><div class="card"><h3>اتصال PasarGuard</h3><div class="field"><label>آدرس پنل مرکزی</label><input id="pgUrl" class="ltr" placeholder="https://panel.example.com"></div><div class="grid"><div class="field"><label>نام کاربری مالک</label><input id="pgUser" class="ltr"></div><div class="field"><label>رمز مالک</label><input id="pgPass" class="ltr" type="password"></div></div><div class="field"><label>API Key نسخه ۵.۱ یا Access Token اختیاری</label><input id="pgToken" class="ltr" type="password"><div class="muted">API Key جدید با pg_key_ شروع می‌شود؛ در صورت ثبت آن، درخواست‌های مدیریتی با X-Api-Key ارسال می‌شوند.</div></div><div class="grid"><div class="field"><label>Role ID نمایندگی</label><input id="roleId" class="ltr"></div><div class="field"><label>یا نام Role</label><input id="roleName"></div></div></div><div class="card"><h3>GitHub و آپدیت خودکار</h3><div class="field"><label>مخزن GitHub</label><input id="repo" class="ltr" value="golb4212-design/pasarguard"></div><div class="field"><label>Cloudflare Account ID</label><input id="cfAccount" class="ltr"></div><div class="field"><label>نام Worker</label><input id="cfWorker" class="ltr"></div><div class="field"><label>نام Python Worker؛ اختیاری</label><input id="pythonWorker" class="ltr" placeholder="به‌صورت خودکار از نام Worker ساخته می‌شود"></div><div class="field"><label>Cloudflare API Token</label><input id="cfToken" class="ltr" type="password"></div><div class="muted">بعد از ثبت این اطلاعات، فایل Python Worker و Binding آن همراه با بروزرسانی‌ها خودکار ساخته می‌شوند. API Token باید مجوز Workers Scripts Write داشته باشد و نیازی به pywrangler نیست.</div><button type="submit">نصب و ذخیره تنظیمات</button></div></form></div><script>var q=function(x){return document.getElementById(x)};async function req(path,opt){var r=await fetch(path,opt);var raw=await r.text();var d;try{d=JSON.parse(raw)}catch(_){throw new Error('پاسخ نامعتبر از Worker (HTTP '+r.status+'): '+(raw||'بدون پاسخ').slice(0,220))}if(!r.ok||d.success===false){var e=new Error(d.error||('خطای HTTP '+r.status));e.code=d.code;e.channels=d.channels||[];throw e}return d}async function init(){try{var s=await req('/api/setup/status');if(s.installed){q('status').innerHTML='<b class="ok">نصب قبلاً تکمیل شده است.</b><div class="muted">ربات مستقل و مینی‌اپ هر دو آماده استفاده هستند.</div>';return}q('status').innerHTML='<b>آماده نصب</b><div class="muted">پس از نصب، این صفحه قفل می‌شود.</div>';q('form').style.display='block';q('appUrl').value=location.origin+'/app'}catch(e){q('status').innerHTML='<b class="err">'+e.message+'</b><div class="muted">ابتدا /health را باز کنید. اگر binding_detected برابر false بود، پس از اتصال D1 یک بار Save and Deploy را بزنید.</div>'}}q('form').onsubmit=async function(e){e.preventDefault();try{var body={setup_password:q('setupPassword').value,admin_ids:q('adminIds').value,bot_token:q('botToken').value,app_url:q('appUrl').value,brand_name:q('brand').value,price_per_gb:q('price').value,setup_fee:q('fee').value,min_recharge:q('minRecharge').value,blupal_base_url:q('blupalBase').value,blupal_api_key:q('blupalApiKey').value,blupal_card_number:q('blupalCard').value,pasarguard_panel_url:q('pgUrl').value,pasarguard_admin_username:q('pgUser').value,pasarguard_admin_password:q('pgPass').value,pasarguard_access_token:q('pgToken').value,pasarguard_reseller_role_id:q('roleId').value,pasarguard_reseller_role_name:q('roleName').value,github_repo:q('repo').value,cf_account_id:q('cfAccount').value,cf_worker_name:q('cfWorker').value,cf_api_token:q('cfToken').value,python_helper_worker_name:q('pythonWorker').value};var d=await req('/api/setup/install',{method:'POST',headers:{'content-type':'application/json'},body:JSON.stringify(body)});q('form').style.display='none';var pyMessage=d.python_helper&&d.python_helper.success?'Python Worker و Binding آن خودکار ساخته شدند.':'ساخت Python Worker در پس‌زمینه ادامه پیدا می‌کند؛ وضعیت آن از مدیریت قابل مشاهده است.';q('status').innerHTML='<b class="ok">نصب با موفقیت انجام شد.</b><div class="muted">گزارش مراحل نصب نیز برای مدیران ربات ارسال شد.</div><div class="muted">Webhook بلوپال:</div><div class="webhook ltr">'+d.blupal_webhook_url+'</div><div class="muted">Return URL / Callback URL بلوپال:</div><div class="webhook ltr">'+d.blupal_return_url+'</div><div class="muted">'+pyMessage+'</div>'}catch(err){q('status').innerHTML='<b class="err">'+err.message+'</b>'}};init();</script></body></html>`;



class BluePanelRemoteStatement {
  constructor(binding, sql, params = []) { this.binding = binding; this.sql = String(sql || ''); this.params = params; }
  bind(...params) { return new BluePanelRemoteStatement(this.binding, this.sql, params); }
  async first() { return bluePanelRemoteD1Call(this.binding, { op: 'query', mode: 'first', sql: this.sql, params: this.params }); }
  async all() { return bluePanelRemoteD1Call(this.binding, { op: 'query', mode: 'all', sql: this.sql, params: this.params }); }
  async run() { return bluePanelRemoteD1Call(this.binding, { op: 'query', mode: 'run', sql: this.sql, params: this.params }); }
}
class BluePanelRemoteD1 {
  constructor(binding, sourceRole) { this.binding = binding; this.sourceRole = sourceRole; }
  prepare(sql) { return new BluePanelRemoteStatement(this.binding, sql); }
  async batch(statements) {
    const queries = (statements || []).map(statement => ({ sql: statement.sql, params: statement.params || [] }));
    return bluePanelRemoteD1Call(this.binding, { op: 'batch', queries });
  }
}
async function bluePanelRemoteD1Call(binding, payload) {
  if (!binding || typeof binding.fetch !== 'function') throw new Error('Service Binding با نام CORE_WORKER متصل نیست');
  const response = await binding.fetch(new Request('https://bluepanel-core.internal/__bluepanel/internal/d1', {
    method: 'POST',
    headers: { 'content-type': 'application/json', 'accept': 'application/json', 'x-bluepanel-service-hop': 'split-runtime-d1' },
    body: JSON.stringify(payload)
  }));
  let data = null;
  try { data = await response.json(); } catch (_) {}
  if (!response.ok || !data || data.success === false) throw new Error(data?.error || ('Remote D1 HTTP ' + response.status));
  return data.result;
}
function bluePanelRuntimeEnv(env, role) {
  const out = Object.assign({}, env);
  out.PASARGUARD_DB = new BluePanelRemoteD1(env.CORE_WORKER, role);
  return out;
}
async function ensureDb(env) {
  // Every real query already validates the Service Binding. Avoid a separate SELECT 1
  // before each operation because it doubles remote D1 round-trips on hot paths.
  if (!env?.PASARGUARD_DB || typeof env.PASARGUARD_DB.prepare !== 'function') throw new Error('اتصال دیتابیس مرکزی در دسترس نیست');
  return true;
}

const BLUEPANEL_EDGE_VERSION='3.3.19';
function bluePanelEdgeJson(data,status=200,headers={}){return new Response(JSON.stringify(data),{status,headers:{'content-type':'application/json; charset=utf-8','cache-control':'no-store',...headers}})}
function bluePanelEdgeInternal(request){try{return new URL(request.url).hostname.endsWith('.internal')}catch(_){return false}}
function bluePanelEdgeRuntimeBinding(env,name){const value=env?.[name];return{name,exact_key_present:Object.prototype.hasOwnProperty.call(env||{},name),value_present:value!==undefined&&value!==null,fetch_callable:Boolean(value&&typeof value.fetch==='function'),constructor_name:value?.constructor?.name||''}}
async function bluePanelEdgeLocalHealth(env){let dbOk=false,error='';try{if(!env.EDGE_DB)throw new Error('EDGE_DB متصل نیست');await env.EDGE_DB.prepare('SELECT 1 AS ok').first();dbOk=true}catch(e){error=String(e?.message||e)}const coreBinding=bluePanelEdgeRuntimeBinding(env,'CORE_WORKER'),processorBinding=bluePanelEdgeRuntimeBinding(env,'PROCESSOR_WORKER');const coreDetected=coreBinding.fetch_callable,processorDetected=processorBinding.fetch_callable;return{ok:dbOk,cluster_ready:dbOk&&coreDetected&&processorDetected,role:'bluepanel-edge',version:APP_VERSION,database_query_ok:dbOk,binding_detected:true,core_binding_detected:coreDetected,processor_binding_detected:processorDetected,core_ok:coreDetected,processor_ok:processorDetected,core_probe:{binding_detected:coreDetected,healthy:coreDetected,mode:'runtime_binding_presence',detail:coreDetected?'CORE_WORKER در Runtime شناسایی شد':'CORE_WORKER در Runtime وجود ندارد',error:coreDetected?'':'CORE_WORKER متصل نیست'},processor_probe:{binding_detected:processorDetected,healthy:processorDetected,mode:'runtime_binding_presence',detail:processorDetected?'PROCESSOR_WORKER در Runtime شناسایی شد':'PROCESSOR_WORKER در Runtime وجود ندارد',error:processorDetected?'':'PROCESSOR_WORKER متصل نیست'},runtime_bindings:{CORE_WORKER:coreBinding,PROCESSOR_WORKER:processorBinding},split_runtime:true,bundle:'edge',verification_mode:'cycle_safe_local',error}}
async function bluePanelEdgeProbePeer(binding,url,expectedRole,name){const started=Date.now();if(!binding||typeof binding.fetch!=='function')return{binding_detected:false,healthy:false,reachable:false,latency_ms:0,error:name+' متصل نیست'};try{const timeout=new Promise((_,reject)=>setTimeout(()=>reject(new Error('مهلت پاسخ تمام شد')),2500));const response=await Promise.race([binding.fetch(new Request(url,{headers:{'x-bluepanel-service-hop':'edge-public-health','accept':'application/json'}})),timeout]);const raw=await response.text();let data={};try{data=raw?JSON.parse(raw):{}}catch(_){return{binding_detected:true,healthy:false,reachable:true,http_status:response.status,latency_ms:Date.now()-started,error:'پاسخ JSON نیست'}}const healthy=response.ok&&data.role===expectedRole&&data.database_query_ok!==false;return{binding_detected:true,healthy,reachable:true,http_status:response.status,latency_ms:Date.now()-started,response_role:data.role||'',response_version:data.version||'',error:healthy?'':(data.error||'پاسخ ناسالم')}}catch(e){return{binding_detected:true,healthy:false,reachable:false,latency_ms:Date.now()-started,error:String(e?.message||e)}}}
async function bluePanelEdgeDeepHealth(env){const local=await bluePanelEdgeLocalHealth(env);const [coreProbe,processorProbe]=await Promise.all([bluePanelEdgeProbePeer(env.CORE_WORKER,'https://bluepanel-core.internal/__bluepanel/service/core-local-health','bluepanel-core','CORE_WORKER'),bluePanelEdgeProbePeer(env.PROCESSOR_WORKER,'https://bluepanel-processor.internal/__bluepanel/service/processor-local-health','bluepanel-processor','PROCESSOR_WORKER')]);const coreOk=coreProbe.healthy===true,processorOk=processorProbe.healthy===true;return{...local,ok:local.database_query_ok&&coreOk&&processorOk,cluster_ready:local.database_query_ok&&coreOk&&processorOk,core_ok:coreOk,processor_ok:processorOk,core_probe:coreProbe,processor_probe:processorProbe,verification_mode:'direct_outbound_no_cycle',error:local.error||coreProbe.error||processorProbe.error||''}}
async function bluePanelEdgeForwardCore(request,env){if(!env.CORE_WORKER||typeof env.CORE_WORKER.fetch!=='function')return bluePanelEdgeJson({success:false,error:'CORE_WORKER متصل نیست',code:'CORE_BINDING_MISSING'},503);const source=new URL(request.url),target='https://bluepanel-core.internal'+source.pathname+source.search,base=new Request(target,request),headers=new Headers(base.headers);headers.set('x-bluepanel-service-hop','edge-to-core');headers.set('x-bluepanel-public-origin',request.headers.get('x-bluepanel-public-origin')||source.origin);const r=await env.CORE_WORKER.fetch(new Request(base,{headers,redirect:'manual'}));return new Response(r.body,{status:r.status,statusText:r.statusText,headers:r.headers})}
async function bluePanelQueueResellerWebhook(request,env){if(!env.PROCESSOR_WORKER||typeof env.PROCESSOR_WORKER.fetch!=='function')return null;const source=new URL(request.url),body=await request.clone().text(),headers={};for(const [k,v] of request.headers)if(!['host','content-length'].includes(k.toLowerCase()))headers[k]=v;const r=await env.PROCESSOR_WORKER.fetch(new Request('https://bluepanel-processor.internal/__bluepanel/service/queue',{method:'POST',headers:{'content-type':'application/json','x-bluepanel-service-hop':'edge-to-processor'},body:JSON.stringify({method:request.method,path_query:source.pathname+source.search,headers,body_text:body,public_origin:request.headers.get('x-bluepanel-public-origin')||source.origin})}));if(!r.ok)return null;return new Response(JSON.stringify({ok:true,queued:true}),{status:200,headers:{'content-type':'application/json; charset=utf-8','cache-control':'no-store','x-bluepanel-queued':'processor'}})}
function bluePanelStaticHeaders(type='text/html; charset=utf-8'){return{'content-type':type,'cache-control':'no-store, no-cache, must-revalidate, max-age=0','cdn-cache-control':'no-store','surrogate-control':'no-store','pragma':'no-cache','expires':'0','x-bluepanel-version':APP_VERSION,'x-content-type-options':'nosniff','referrer-policy':'same-origin','permissions-policy':'camera=(),microphone=(),geolocation=()'}}
async function bluePanelSafeResellerWebhook(request,runtime,botId,ctx){
  try{return await resellerSalesWebhook(request,runtime,botId,ctx)}
  catch(error){
    console.error('reseller webhook recovered from fatal error',error);
    // Always acknowledge Telegram. A failing update must not create a retry storm
    // or make every following message look as if the bot is offline.
    return bluePanelEdgeJson({ok:true,recovered:true,role:'bluepanel-edge',version:APP_VERSION,code:'RESELLER_WEBHOOK_RECOVERY'},200)
  }
}
export default {
 async fetch(request,env,ctx){const runtime=bluePanelRuntimeEnv(env,'bluepanel-edge'),url=new URL(request.url),path=url.pathname.replace(/\/+$/,'')||'/';try{
  if(request.method==='OPTIONS')return new Response(null,{status:204,headers:{'access-control-allow-origin':'*','access-control-allow-methods':'GET,POST,OPTIONS','access-control-allow-headers':'content-type,x-telegram-init-data,x-web-session,authorization,x-bluepanel-public-origin'}});
  if((path==='/__bluepanel/service/edge-local-health'||path==='/__bluepanel/service/edge-health')&&bluePanelEdgeInternal(request)){const h=await bluePanelEdgeLocalHealth(env);return bluePanelEdgeJson(h,h.ok?200:503,{'x-bluepanel-role':'bluepanel-edge','x-bluepanel-version':APP_VERSION});}
  if(path==='/health'){const h=await bluePanelEdgeDeepHealth(env);return bluePanelEdgeJson(h,h.ok?200:503);}
  if(path==='/setup'&&request.method==='GET')return new Response(SETUP_HTML,{headers:bluePanelStaticHeaders()});
  if(path==='/manifest.webmanifest'&&request.method==='GET'){await ensureDb(runtime);const s=await getSettings(runtime);return bluePanelEdgeJson({name:s.brand_name||'BluePanel',short_name:'BluePanel',start_url:'/app',scope:'/',display:'standalone',dir:'rtl',lang:'fa',background_color:'#07111f',theme_color:'#1976f3',icons:[{src:'/assets/bluepanel-icon.svg',sizes:'any',type:'image/svg+xml',purpose:'any maskable'}]},200,{'content-type':'application/manifest+json; charset=utf-8'});}
  const salesManifest=path.match(/^\/sales-manifest\/([^/]+)\.webmanifest$/);if(salesManifest&&request.method==='GET'){await ensureDb(runtime);const bot=await getResellerBotById(runtime,decodeURIComponent(salesManifest[1]));if(!bot)return new Response('Not found',{status:404});return bluePanelEdgeJson({name:bot.brand_name||'BluePanel',short_name:cleanText(bot.brand_name||'BluePanel',20),start_url:'/sales-app/'+encodeURIComponent(bot.id),scope:'/',display:'standalone',dir:'rtl',lang:'fa',background_color:'#07111f',theme_color:'#1976f3',icons:[{src:'/assets/bluepanel-icon.svg',sizes:'any',type:'image/svg+xml',purpose:'any maskable'}]},200,{'content-type':'application/manifest+json; charset=utf-8'});}
  if(path==='/assets/bluepanel-icon.svg'&&request.method==='GET'){const svg='<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 512 512"><rect width="512" height="512" rx="116" fill="#07111f"/><circle cx="256" cy="256" r="196" fill="#1976f3"/><path fill="white" d="M151 151h116c62 0 98 27 98 72 0 26-14 46-39 57 34 9 53 33 53 66 0 51-40 80-110 80H151V151zm80 65v45h38c27 0 40-8 40-23 0-15-13-22-40-22h-38zm0 105v47h44c30 0 45-8 45-24 0-15-15-23-45-23h-44z"/></svg>';return new Response(svg,{headers:{'content-type':'image/svg+xml; charset=utf-8','cache-control':'public,max-age=86400'}})}
  if(path==='/sw.js'&&request.method==='GET')return new Response('const V="3.3.13";self.addEventListener("install",e=>self.skipWaiting());self.addEventListener("activate",e=>e.waitUntil((async()=>{for(const k of await caches.keys())await caches.delete(k);await self.clients.claim()})()));self.addEventListener("fetch",e=>{if(e.request.mode==="navigate")e.respondWith(fetch(e.request,{cache:"no-store"}))});',{headers:{'content-type':'application/javascript; charset=utf-8','cache-control':'no-store','service-worker-allowed':'/'}});
  if(['/control','/admin','/panel','/dashboard'].includes(path)&&request.method==='GET')return new Response(CENTRAL_CONTROL_HTML.replaceAll('__APP_VERSION__',APP_VERSION),{headers:bluePanelStaticHeaders()});
  if(path==='/control-advanced'&&request.method==='GET')return new Response(MINI_APP_HTML.replaceAll('__APP_VERSION__',APP_VERSION).replaceAll('__CONTROL_MODE__','true'),{headers:bluePanelStaticHeaders()});
  if(['/', '/app','/miniapp'].includes(path)&&request.method==='GET')return new Response(MINI_APP_HTML.replaceAll('__APP_VERSION__',APP_VERSION).replaceAll('__CONTROL_MODE__','false'),{headers:bluePanelStaticHeaders()});
  const wh=path.match(/^\/sales-bot\/([^/]+)\/webhook$/);if(wh&&request.method==='POST')return bluePanelSafeResellerWebhook(request,runtime,decodeURIComponent(wh[1]),ctx);
  const pwh=path.match(/^\/sales-payments\/([^/]+)\/blupal\/webhook$/);if(pwh&&request.method==='POST')return resellerBlupalWebhook(request,runtime,ctx,decodeURIComponent(pwh[1]));
  const ccback=path.match(/^\/sales-payments\/([^/]+)\/cubepay\/callback$/);if(ccback&&['GET','POST'].includes(request.method))return resellerCubepayCallback(request,runtime,decodeURIComponent(ccback[1]));
  const pcback=path.match(/^\/sales-payments\/([^/]+)\/plisio\/callback$/);if(pcback&&request.method==='POST')return resellerPlisioCallback(request,runtime,decodeURIComponent(pcback[1]));
  const pcret=path.match(/^\/sales-payments\/([^/]+)\/plisio\/return$/);if(pcret&&request.method==='GET'){await ensureDb(runtime);const bot=await getResellerBotById(runtime,decodeURIComponent(pcret[1]));if(!bot)return new Response('Not found',{status:404});return new Response(resellerPlisioReturnPage(bot,request.headers.get('x-bluepanel-public-origin')||url.origin,url),{headers:bluePanelStaticHeaders()});}
  const pret=path.match(/^\/sales-payments\/([^/]+)\/return$/);if(pret&&request.method==='GET'){await ensureDb(runtime);const bot=await getResellerBotById(runtime,decodeURIComponent(pret[1]));if(!bot)return new Response('Not found',{status:404});return new Response(resellerBlupalReturnPage(bot,request.headers.get('x-bluepanel-public-origin')||url.origin),{headers:bluePanelStaticHeaders()});}
  const auth=path.match(/^\/reseller-control-auth\/([^/]+)\/(login|logout)$/);if(auth&&request.method==='POST')return auth[2]==='login'?resellerAdminWebLogin(request,runtime,decodeURIComponent(auth[1])):resellerAdminWebLogout(request,runtime,decodeURIComponent(auth[1]));
  const page=path.match(/^\/reseller-control\/([^/]+)$/);if(page&&request.method==='GET'){await ensureDb(runtime);const botId=decodeURIComponent(page[1]),bot=await getResellerBotById(runtime,botId);if(!bot)return new Response('Not found',{status:404});return new Response(RESELLER_CONTROL_HTML.replaceAll('__BOT_ID__',botId).replaceAll('__APP_VERSION__',APP_VERSION),{headers:bluePanelStaticHeaders()});}
  const api=path.match(/^\/reseller-control-api\/([^/]+)\/(bootstrap|action)$/);if(api){const botId=decodeURIComponent(api[1]);if(api[2]==='bootstrap'&&request.method==='GET')return resellerAdminBootstrap(request,runtime,botId);if(api[2]==='action'&&request.method==='POST')return resellerAdminAction(request,runtime,botId);}
  const receipt=path.match(/^\/reseller-control-api\/([^/]+)\/receipt\/(order|wallet)\/([^/]+)$/);if(receipt&&request.method==='GET')return resellerAdminReceipt(request,runtime,decodeURIComponent(receipt[1]),receipt[2],decodeURIComponent(receipt[3]));
  const sa=path.match(/^\/sales-auth\/([^/]+)\/(request-code|verify-code|logout)$/);if(sa&&request.method==='POST'){const botId=decodeURIComponent(sa[1]);if(sa[2]==='request-code')return salesWebRequestCode(request,runtime,botId);if(sa[2]==='verify-code')return salesWebVerifyCode(request,runtime,botId);return salesWebLogout(request,runtime,botId);}
  const sapp=path.match(/^\/sales-app\/([^/]+)$/);if(sapp&&request.method==='GET'){await ensureDb(runtime);const botId=decodeURIComponent(sapp[1]),bot=await getResellerBotById(runtime,botId);if(!bot||Number(bot.miniapp_enabled??1)!==1)return new Response('Mini App unavailable',{status:404});return new Response(SALES_MINI_APP_HTML.replaceAll('__BOT_ID__',botId),{headers:bluePanelStaticHeaders()});}
  const sapi=path.match(/^\/sales-api\/([^/]+)\/(bootstrap|action)$/);if(sapi&&request.method==='POST'){const botId=decodeURIComponent(sapi[1]);return sapi[2]==='bootstrap'?salesMiniAppBootstrap(request,runtime,botId,ctx):salesMiniAppAction(request,runtime,botId,ctx);}
  return bluePanelEdgeForwardCore(request,env);
 }catch(error){console.error('edge fetch error',error);return bluePanelEdgeJson({success:false,ok:false,role:'bluepanel-edge',version:APP_VERSION,error:String(error?.message||error),code:'EDGE_RUNTIME_ERROR'},500)}}
};
